-- Schema for Domain: sponsorship | Business: Sports Entertainment | Version: v1_mvm
-- Generated on: 2026-05-09 04:52:11

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `sports_entertainment_ecm`.`sponsorship` COMMENT 'Partnership and commercial domain managing B2B sponsor contracts, brand activations, advertising inventory, naming rights, and partnership fulfillment. Owns sponsor identity, deal terms, activation deliverables, performance metrics (CPM, GRP), ROI tracking, jersey sponsorships, venue naming rights, broadcast integrations, and digital platform partnerships. Manages the full sponsorship lifecycle from prospecting through renewal.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`sponsorship`.`sponsor` (
    `sponsor_id` BIGINT COMMENT 'Unique surrogate identifier for the sponsoring organization or brand. Primary key for the sponsor master record across all commercial and activation workflows.',
    `operator_id` BIGINT COMMENT 'Foreign key linking to gaming.operator. Business justification: Gaming operators (DraftKings, FanDuel) are major sponsors. Compliance and exclusivity enforcement require knowing if a sponsor is a licensed gaming operator. Sponsorship teams screen operator license ',
    `account_tier` STRING COMMENT 'Commercial tier classification of the sponsorship relationship indicating the level of investment, exclusivity, and activation rights. Title sponsors receive the highest prominence; associate sponsors receive baseline rights. Drives benefit entitlement and activation priority.. Valid values are `title|presenting|official|associate|founding`',
    `activation_region` STRING COMMENT 'Geographic scope of the sponsors activation rights (e.g., Global, North America, USA, GBR, DEU). Determines where brand activations, broadcast integrations, and digital placements may be executed. Uses ISO 3166-1 alpha-3 for country-level or named region for multi-country scopes.',
    `agency_name` STRING COMMENT 'Name of the sports marketing or media agency representing the sponsor in deal negotiations and activation management (e.g., IMG, Octagon, WME Sports). Relevant when the sponsor engages through an intermediary rather than directly.',
    `annual_investment_usd` DECIMAL(18,2) COMMENT 'Total contracted annual cash investment value of the sponsorship in US Dollars. Represents the base financial commitment excluding value-in-kind (VIK) contributions. Used for revenue forecasting, EBITDA (Earnings Before Interest Taxes Depreciation and Amortization) reporting, and tier qualification.',
    `brand_name` STRING COMMENT 'Commercial or trade name of the sponsor brand as displayed in activations, signage, broadcast integrations, and fan-facing materials. May differ from the legal entity name (e.g., parent company vs. product brand).',
    `broadcast_integration_flag` BOOLEAN COMMENT 'Indicates whether this sponsor has contracted broadcast integration rights including virtual signage, sponsored segments, on-screen billboards, or OTT (Over-The-Top Streaming) branded content placements.',
    `category_exclusivity_flag` BOOLEAN COMMENT 'Indicates whether this sponsor holds exclusive rights within their industry category, preventing competing brands in the same category from entering into sponsorship agreements. Critical for conflict-of-interest checks during new deal prospecting.',
    `created_timestamp` TIMESTAMP COMMENT 'UTC timestamp when the sponsor master record was first created in the system. Supports data lineage, audit trail requirements, and SOX financial control documentation.',
    `crm_account_code` STRING COMMENT 'Salesforce CRM Account record identifier linking this sponsor to the authoritative B2B relationship record in Salesforce CRM. Used for bi-directional sync of contact, opportunity, and activity data.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code in which the sponsorship contract is denominated (e.g., USD, GBP, EUR). Used for multi-currency financial reporting and FX conversion in consolidated revenue statements.. Valid values are `^[A-Z]{3}$`',
    `data_privacy_consent_flag` BOOLEAN COMMENT 'Indicates whether the sponsoring organizations primary contact has provided consent for data processing activities under applicable privacy regulations. Required for GDPR-compliant B2B contact data management in EU markets.',
    `digital_platform_flag` BOOLEAN COMMENT 'Indicates whether this sponsor has contracted digital platform partnership rights including DTC (Direct-To-Consumer) app integrations, social media activations, OTT branded content, or API-driven data partnerships.',
    `exclusivity_category` STRING COMMENT 'The specific product or service category for which this sponsor holds exclusivity rights (e.g., Official Beer, Official Automotive Partner, Official Financial Services Partner). Populated only when category_exclusivity_flag is true. Used to enforce category conflict checks during new deal origination.',
    `gdpr_applicable_flag` BOOLEAN COMMENT 'Indicates whether GDPR (General Data Protection Regulation) applies to this sponsor relationship based on the sponsors headquarters jurisdiction or the markets in which activations are executed. Triggers enhanced data handling and consent management workflows.',
    `headquarters_city` STRING COMMENT 'City of the sponsors global headquarters. Used for geographic market analysis, regional partnership segmentation, and event proximity reporting.',
    `headquarters_country` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the sponsors global headquarters. Used for jurisdictional compliance (GDPR, CCPA), tax treaty application, and international partnership reporting.. Valid values are `^[A-Z]{3}$`',
    `headquarters_state_province` STRING COMMENT 'State or province of the sponsors global headquarters. Used for regional market segmentation, tax jurisdiction determination, and compliance with state-level privacy laws such as CCPA.',
    `industry_category` STRING COMMENT 'Primary industry sector of the sponsoring organization using standard classification (e.g., Automotive, Financial Services, Consumer Packaged Goods, Technology, Telecommunications, Apparel). Used for category exclusivity management and competitive conflict checks. [ENUM-REF-CANDIDATE: automotive|financial_services|consumer_packaged_goods|technology|telecommunications|apparel|healthcare|food_beverage|insurance|retail|energy|media — promote to reference product]',
    `is_publicly_traded` BOOLEAN COMMENT 'Indicates whether the sponsoring organization is a publicly traded company listed on a recognized stock exchange. Drives SEC disclosure obligations, financial due diligence requirements, and SOX compliance considerations.',
    `jersey_sponsorship_flag` BOOLEAN COMMENT 'Indicates whether this sponsor holds jersey or kit sponsorship rights for one or more teams or athletes. Jersey sponsorships carry premium brand visibility and are governed by league IP and uniform regulations.',
    `legal_name` STRING COMMENT 'Full registered legal name of the sponsoring organization as it appears on executed contracts and regulatory filings. Used for invoicing, contract execution, and compliance reporting.',
    `naics_code` STRING COMMENT 'Six-digit NAICS code identifying the sponsors primary business activity. Used for industry benchmarking, regulatory reporting, and category exclusivity conflict detection.. Valid values are `^[0-9]{6}$`',
    `naming_rights_flag` BOOLEAN COMMENT 'Indicates whether this sponsor holds naming rights for one or more venues. Naming rights are among the highest-value sponsorship assets and require specific contractual, signage, and broadcast integration management.',
    `nil_partnership_flag` BOOLEAN COMMENT 'Indicates whether this sponsor has active NIL (Name, Image, and Likeness) agreements with individual athletes managed through the sports-entertainment ecosystem. NIL deals require separate compliance tracking under applicable state laws and league policies.',
    `nps_score` STRING COMMENT 'Most recent NPS (Net Promoter Score) survey result from the sponsoring organization, ranging from -100 to 100. Measures sponsor satisfaction and likelihood to renew or expand the partnership. Collected via annual partner satisfaction surveys.',
    `parent_organization_name` STRING COMMENT 'Name of the ultimate parent corporation in the sponsors corporate hierarchy. Supports consolidated revenue reporting, conflict-of-interest checks, and category exclusivity enforcement across subsidiary brands.',
    `preferred_language` STRING COMMENT 'BCP 47 language tag representing the sponsors preferred language for contract communications, activation briefs, and reporting (e.g., en, fr, de, es). Supports multilingual partnership management across global markets.. Valid values are `^[a-z]{2}(-[A-Z]{2})?$`',
    `prospecting_source` STRING COMMENT 'Channel or method through which this sponsor was originally identified or acquired. Used for CAC (Customer Acquisition Cost) analysis, sales pipeline attribution, and partnership development strategy reporting. [ENUM-REF-CANDIDATE: inbound|outbound|referral|agency|renewal|conference|other — 7 candidates stripped; promote to reference product]',
    `relationship_start_date` DATE COMMENT 'Calendar date on which the first commercial sponsorship relationship with this organization was established. Supports tenure calculations, loyalty tier assessments, and long-term partner recognition programs.',
    `relationship_status` STRING COMMENT 'Current lifecycle status of the sponsor relationship. Drives workflow routing, activation eligibility, and CRM pipeline reporting. Prospect indicates pre-contract; active indicates a live deal; suspended indicates a temporary hold; terminated indicates a closed relationship.. Valid values are `prospect|active|inactive|suspended|terminated|renewed`',
    `renewal_probability` DECIMAL(18,2) COMMENT 'Estimated probability (0.00–100.00) that the sponsor will renew their agreement at the end of the current contract term. Assessed by the account manager and updated in Salesforce CRM. Used for revenue forecasting and pipeline management.',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this sponsor master record was originated or last updated. Supports data lineage tracking and master data management reconciliation across Salesforce CRM and SAP S/4HANA.. Valid values are `salesforce_crm|sap_s4hana|manual|migration|other`',
    `stock_ticker` STRING COMMENT 'Exchange-listed stock ticker symbol for publicly traded sponsoring organizations. Used for financial health monitoring, SEC disclosure cross-referencing, and investor relations reporting.. Valid values are `^[A-Z]{1,5}$`',
    `updated_timestamp` TIMESTAMP COMMENT 'UTC timestamp when the sponsor master record was most recently modified. Used for change data capture (CDC), data freshness monitoring, and audit trail compliance.',
    `value_in_kind_usd` DECIMAL(18,2) COMMENT 'Estimated USD value of non-cash contributions provided by the sponsor in lieu of or in addition to cash investment (e.g., product supply, media inventory, technology services). Included in total deal value calculations and EBITDA reporting.',
    `wada_compliance_flag` BOOLEAN COMMENT 'Indicates whether this sponsor is subject to WADA (World Anti-Doping Agency) compliance requirements due to NIL athlete partnerships or direct involvement in athlete performance programs. Triggers PED (Performance Enhancing Drug) policy review obligations.',
    `website_url` STRING COMMENT 'Official public website URL of the sponsoring organization or brand. Used for digital activation link-throughs, brand verification, and partner directory listings.. Valid values are `^https?://[^s/$.?#].[^s]*$`',
    CONSTRAINT pk_sponsor PRIMARY KEY(`sponsor_id`)
) COMMENT 'Master record for all sponsoring organizations and brands in the sports-entertainment ecosystem. Captures sponsor identity, corporate hierarchy, industry classification, account tier (title, presenting, official, associate), CRM account linkage from Salesforce, contact details, and relationship status. SSOT for sponsor identity across all commercial and activation workflows.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`sponsorship`.`deal` (
    `deal_id` BIGINT COMMENT 'Unique surrogate identifier for the sponsorship deal record in the Databricks Silver Layer. Primary key for the deal entity.',
    `budget_id` BIGINT COMMENT 'Foreign key linking to finance.budget. Business justification: Sponsorship deals are planned against finance budgets for annual revenue forecasting and variance reporting. Sports finance teams track contracted deal value vs. budgeted sponsorship revenue by season',
    `obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.obligation. Business justification: Sponsorship deals create specific compliance obligations (WADA NIL rules, FCC broadcast disclosure, GDPR data sharing). Linking a deal to its primary compliance obligation enables obligation tracking,',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Sponsorship deals incur costs (activation, fulfillment, account management) tracked against cost centers for P&L reporting by business unit. Finance requires cost center assignment on deals for budget',
    `segment_id` BIGINT COMMENT 'Foreign key linking this targeting commitment to the fan segment being targeted under the sponsorship deal.',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Franchise-level sponsorship deals (jersey patches, team naming rights, franchise broadcast integrations) are a primary commercial structure in sports. Deal.league_id exists but franchise-specific deal',
    `governing_body_id` BIGINT COMMENT 'Foreign key linking to compliance.governing_body. Business justification: Sponsorship deals (naming rights, broadcast integrations, NIL) must comply with the rules of the relevant governing body (NFL, FIFA, FCC). Deal managers need to know which governing bodys rules apply',
    `jurisdiction_id` BIGINT COMMENT 'Foreign key linking to gaming.gaming_jurisdiction. Business justification: Sponsorship deals with betting operators are jurisdiction-scoped — activations are only permitted in jurisdictions where the operator holds a license. Compliance teams validate deal activations agains',
    `league_id` BIGINT COMMENT 'Reference to the league or competition entity associated with this sponsorship deal. Applicable for league-level sponsorships, official partner designations, and league division naming rights.',
    `media_rights_deal_id` BIGINT COMMENT 'Foreign key linking to broadcast.media_rights_deal. Business justification: Sponsorship deals with broadcast integration rights must be validated against the underlying media rights deal covering that territory and platform. Linking enables compliance checking that sponsorshi',
    `operator_id` BIGINT COMMENT 'Foreign key linking to gaming.operator. Business justification: Sponsorship deals with gaming operators require referencing operator license status, responsible gaming certifications, and jurisdiction coverage for regulatory compliance and deal structuring. Legal ',
    `policy_id` BIGINT COMMENT 'Foreign key linking to compliance.policy. Business justification: Sponsorship deals must comply with internal policies (brand safety, data privacy, anti-doping, anti-corruption). Linking a deal to its governing compliance policy enables policy version tracking, atte',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Sponsorship deal revenue is attributed to specific profit centers (by league, property, or region) for segment reporting and management accounts. Finance requires profit center assignment on deals for',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Sponsorship deals are season-scoped contracts — annual partnerships, season-long broadcast integrations, and performance obligations are all tied to a specific league season. Season-level deal reporti',
    `sponsor_id` BIGINT COMMENT 'Reference to the sponsor (brand or corporate entity) that is party to this commercial agreement. Links to the sponsor master record.',
    `venue_id` BIGINT COMMENT 'Reference to the venue or facility asset associated with this deal, particularly for naming rights and venue-based activation deals. Links to the venue master record.',
    `activation_deliverables_summary` STRING COMMENT 'High-level summary of the key activation deliverables committed under this deal (e.g., jersey patch, LED signage, broadcast mentions, social media posts, hospitality packages). Supports fulfillment tracking and partner reporting.',
    `annual_contract_value` DECIMAL(18,2) COMMENT 'Annualized monetary value of the sponsorship deal, derived from TCV divided by contract term years. Used for ARR reporting, budget planning in Workday Adaptive Planning, and year-over-year comparisons.',
    `arpu_impact_estimate` DECIMAL(18,2) COMMENT 'Estimated incremental ARPU attributable to the digital sponsorship activation, expressed in deal currency. Used for DTC and OTT partnership ROI modeling and Workday Adaptive Planning forecasts.',
    `audience_commitment_size` BIGINT COMMENT 'The contractually committed number of fan profiles from this segment that the deal is obligated to reach during the targeting flight window. This is a per-segment-per-deal contractual figure that belongs to the targeting relationship, not to the deal total or the segments overall fan_count.',
    `audience_delivery_status` STRING COMMENT 'Current fulfillment state of the audience commitment for this segment-deal pairing. Tracks whether the contractual audience reach obligation is being met. Belongs to the targeting relationship — a segment may be fully delivered under one deal while underdelivered under another simultaneously.',
    `broadcast_mention_requirement` STRING COMMENT 'Contractual specification for how and how often the sponsor or named asset must be verbally or visually referenced during broadcast coverage (e.g., Minimum 3 verbal mentions per broadcast hour). Applicable to naming rights and broadcast integration deals.',
    `campaign_flight_end_date` DATE COMMENT 'End date of the active campaign flight period for digital partnership activations. Defines the window during which impression and CTR commitments must be fulfilled.',
    `campaign_flight_start_date` DATE COMMENT 'Start date of the active campaign flight period for digital partnership activations. May differ from the overall deal start date if the digital campaign runs within a sub-window of the contract term.',
    `contract_document_reference` STRING COMMENT 'Reference identifier or URL to the executed contract document stored in the document management system. Enables audit trail and legal review access for SOX and SEC compliance.',
    `cpm_rate` DECIMAL(18,2) COMMENT 'Negotiated Cost Per Mille (CPM) rate for digital and broadcast impression-based activations under this deal, expressed in deal currency per 1,000 impressions. Used for ROI benchmarking and media value reporting.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the deal record was first created in the system. Used for audit trail, data lineage, and pipeline age reporting.',
    `ctr_target` DECIMAL(18,2) COMMENT 'Contractually committed click-through rate target for digital sponsorship activations, expressed as a decimal proportion (e.g., 0.0250 = 2.50%). Applicable to digital platform partnership deals. Used for performance benchmarking and ROI reporting.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary values on this deal (e.g., USD, EUR, GBP). Required for multi-territory deals and SAP FI currency translation.. Valid values are `^[A-Z]{3}$`',
    `data_sharing_consent_scope` STRING COMMENT 'GDPR/CCPA-compliant scope of fan data that may be shared with the sponsor under this deal. Governs data exchange in digital platform partnerships and Adobe Experience Platform personalization activations. Values: none, anonymized_aggregate, pseudonymized, identified_opt_in, full_consent.. Valid values are `none|anonymized_aggregate|pseudonymized|identified_opt_in|full_consent`',
    `deal_name` STRING COMMENT 'Human-readable commercial name of the sponsorship deal (e.g., Acme Corp Jersey Sponsorship 2025, GlobalBank Arena Naming Rights). Used in reporting, presentations, and CRM.',
    `deal_type` STRING COMMENT 'Classification of the sponsorship deal by commercial category. Determines which sub-type attributes are applicable and drives activation workflows. Values: jersey_sponsorship, venue_naming_rights, broadcast_integration, digital_platform_partnership, presenting_sponsor, official_partner.. Valid values are `jersey_sponsorship|venue_naming_rights|broadcast_integration|digital_platform_partnership|presenting_sponsor|official_partner`',
    `digital_partnership_type` STRING COMMENT 'Sub-classification of digital platform partnership deals. Specifies the nature of the digital activation: app title sponsor, OTT streaming sponsor, social media co-branding, DTC campaign integration, API data partnership, or Adobe Experience Platform personalization. Values: app_title_sponsor, ott_streaming_sponsor, social_media_co_branding, dtc_campaign_integration, api_data_partnership, adobe_personalization.. Valid values are `app_title_sponsor|ott_streaming_sponsor|social_media_co_branding|dtc_campaign_integration|api_data_partnership|adobe_personalization`',
    `digital_property_url` STRING COMMENT 'Web URL of the digital property associated with the deal, such as a renamed stadium website, OTT platform landing page, or DTC campaign microsite. Applicable to naming rights and digital platform partnership deals.',
    `effective_end_date` DATE COMMENT 'The date on which this segment targeting commitment expires under the sponsorship deal. May differ from the deals overall end_date if segment targeting is scoped to a specific campaign flight.',
    `effective_start_date` DATE COMMENT 'The date on which this segment targeting commitment becomes active under the sponsorship deal. May differ from the deals overall start_date if segment targeting is phased or campaign-flight-specific.',
    `end_date` DATE COMMENT 'Calendar date on which the sponsorship deal expires and contractual obligations cease. Nullable for multi-year rolling agreements. Drives renewal pipeline alerts.',
    `exclusivity_category` STRING COMMENT 'Industry or product category within which the sponsor holds exclusive rights (e.g., Financial Services, Automotive, Telecommunications). Prevents conflicting sponsor activations within the same category. [ENUM-REF-CANDIDATE: financial_services|automotive|telecommunications|beverage|apparel|technology|insurance|energy|retail|healthcare — promote to reference product]',
    `exclusivity_scope` STRING COMMENT 'Geographic or organizational scope of the sponsors exclusivity rights. Determines where competing sponsors in the same category may not be activated. Values: global, national, regional, local, league, team, event. [ENUM-REF-CANDIDATE: global|national|regional|local|league|team|event — 7 candidates stripped; promote to reference product]',
    `executed_timestamp` TIMESTAMP COMMENT 'Date and time at which the sponsorship deal was formally executed (signed by all parties). Represents the principal business event timestamp for this agreement. Used for revenue recognition and legal effective date tracking.',
    `grp_commitment` DECIMAL(18,2) COMMENT 'Total Gross Rating Points (GRP) committed to the sponsor for broadcast and media activations under this deal. GRP = Reach % × Frequency. Used for broadcast integration performance tracking and ROI reporting.',
    `hospitality_entitlements` STRING COMMENT 'Description of VIP hospitality entitlements included in the deal (e.g., number of suite tickets, GA tickets, VIP passes, meet-and-greet access per event). Managed through Archtics venue inventory.',
    `impression_commitment` BIGINT COMMENT 'Total number of guaranteed digital or broadcast impressions committed to the sponsor under the deal terms. Used for CPM and GRP performance tracking and ROI reporting.',
    `ip_rights_included` BOOLEAN COMMENT 'Indicates whether the deal grants the sponsor rights to use Sports Entertainments Intellectual Property (IP), including logos, trademarks, team marks, and league marks in their own marketing and advertising.',
    `named_asset` STRING COMMENT 'For venue naming rights deals: the specific asset whose name is being licensed to the sponsor (e.g., stadium, arena, practice facility, trophy, award, league division). Null or none for non-naming-rights deal types. [ENUM-REF-CANDIDATE: stadium|arena|practice_facility|trophy|award|league_division|none — 7 candidates stripped; promote to reference product]',
    `nil_rights_included` BOOLEAN COMMENT 'Indicates whether the deal includes Name, Image, and Likeness (NIL) rights for athletes or talent associated with the sponsoring entitys activations. Relevant for athlete endorsement components of sponsorship deals.',
    `payment_schedule_type` STRING COMMENT 'Defines the contractual payment cadence for the deals total contract value. Drives accounts receivable scheduling in SAP S/4HANA FI and cash flow forecasting in Workday Adaptive Planning.. Valid values are `upfront|annual|quarterly|monthly|milestone_based`',
    `renewal_option_deadline` DATE COMMENT 'Date by which the sponsor must exercise their contractual renewal option. Null if renewal_option_flag is false. Drives CRM renewal pipeline alerts in Salesforce.',
    `renewal_option_flag` BOOLEAN COMMENT 'Indicates whether the deal includes a contractual renewal option clause that grants the sponsor the right of first refusal or automatic renewal at defined terms.',
    `renewal_option_terms` STRING COMMENT 'Summary description of the contractual renewal option terms, including any escalation clauses, right-of-first-refusal conditions, or pricing adjustments applicable upon renewal.',
    `salesforce_opportunity_code` STRING COMMENT 'Reference to the originating opportunity record in Salesforce CRM (Fan and Sponsor Relationship Management). Enables traceability from prospecting through deal execution.',
    `signage_specification` STRING COMMENT 'Description of physical or digital signage deliverables committed under the deal, including placement locations, dimensions, and display frequency (e.g., LED perimeter board, 4 placements, 30-second rotation). Applicable to venue and broadcast deals.',
    `stage` STRING COMMENT 'Current lifecycle stage of the sponsorship deal from initial prospecting through renewal. Drives pipeline reporting and revenue recognition scheduling. Values: prospecting, negotiation, executed, active, expired, renewed.. Valid values are `prospecting|negotiation|executed|active|expired|renewed`',
    `start_date` DATE COMMENT 'Calendar date on which the sponsorship deal becomes effective and contractual obligations commence. Used for revenue recognition scheduling and activation planning.',
    `targeting_priority` STRING COMMENT 'The priority rank of this fan segment within the deals overall audience targeting strategy. Indicates whether this segment is the primary audience commitment or a supplemental targeting layer. Belongs to the relationship, not to the deal or segment independently.',
    `territory` STRING COMMENT 'ISO 3166-1 alpha-3 country code representing the primary territory in which the sponsorship deal is active and rights are granted. For multi-territory deals, references the primary market.. Valid values are `^[A-Z]{3}$`',
    `total_contract_value` DECIMAL(18,2) COMMENT 'Total committed monetary value of the sponsorship deal across its full term, expressed in the deal currency. Key metric for pipeline valuation, EBITDA forecasting, and ARR reporting.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when the deal record was last modified. Used for change data capture (CDC) in the Databricks Silver Layer pipeline and audit compliance.',
    CONSTRAINT pk_deal PRIMARY KEY(`deal_id`)
) COMMENT 'Core sponsorship deal record representing a negotiated commercial agreement between Sports Entertainment and a sponsor. Captures deal name, deal type (jersey sponsorship, venue naming rights, broadcast integration, digital platform partnership, presenting sponsor, official partner), total contract value (TCV), deal stage (prospecting, negotiation, executed, active, expired, renewed), start and end dates, exclusivity category and scope, territory. For naming rights deals: named asset (stadium, arena, practice facility, trophy, award, league division), signage specifications, broadcast mention requirements, digital property URL changes, and renewal option details. For digital partnerships: partnership type (app title sponsor, OTT streaming sponsor, social media co-branding, DTC campaign integration, API data partnership, Adobe Experience Platform personalization), digital property, impression commitment, CTR target, ARPU impact estimate, GDPR/CCPA data-sharing consent scope, and campaign flight dates. Includes originating Salesforce opportunity reference and renewal option flags. Central entity in the sponsorship lifecycle from prospecting through renewal, encompassing all deal sub-types.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`sponsorship`.`deal_term` (
    `deal_term_id` BIGINT COMMENT 'Unique surrogate identifier for a sponsorship deal term record in the Silver Layer lakehouse. Primary key for this entity.',
    `deal_id` BIGINT COMMENT 'Reference to the parent sponsorship deal or contract to which these terms belong. Links deal terms to the overarching sponsorship agreement.',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Deal terms are often franchise-specific — jersey placement obligations, in-arena signage specs, and performance bonuses apply to a specific franchise. Franchise-level term enforcement, compliance audi',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Deal terms specify cash fees, VIK amounts, and performance bonuses that must post to distinct GL accounts (cash sponsorship revenue vs. VIK revenue vs. bonus income). Revenue classification by GL acco',
    `governing_body_id` BIGINT COMMENT 'Foreign key linking to compliance.governing_body. Business justification: Individual deal terms (exclusivity clauses, NIL rights, broadcast integration terms) are governed by specific governing body rules. Linking each term to its governing body enables compliance teams to ',
    `jurisdiction_id` BIGINT COMMENT 'Foreign key linking to gaming.gaming_jurisdiction. Business justification: Deal terms for betting operator sponsors are jurisdiction-specific: tax treatment, permitted activation scope, and responsible gaming obligations vary by jurisdiction. Legal teams validate deal terms ',
    `league_id` BIGINT COMMENT 'Foreign key linking to league.league. Business justification: Deal terms define contractual obligations (NIL policy, exclusivity, CBA compliance) governed by a specific league. Compliance teams validate deal terms against league rules directly; league context sh',
    `license_id` BIGINT COMMENT 'Foreign key linking to content.license. Business justification: Sponsorship deal terms granting IP or broadcast clip rights must reference the corresponding content license. Rights management teams reconcile deal_term IP rights flags against content.license record',
    `nil_agreement_id` BIGINT COMMENT 'Foreign key linking to athlete.nil_agreement. Business justification: Deal terms with nil_athlete_rights_flag govern specific NIL agreements. Contract management and compliance teams must link deal terms to the exact NIL agreement they authorize, enabling NIL rights aud',
    `operator_id` BIGINT COMMENT 'Foreign key linking to gaming.operator. Business justification: Deal terms with gaming operators include operator-specific clauses (license requirements, responsible gaming mandates). Compliance teams reference the operator record when auditing or enforcing indivi',
    `policy_id` BIGINT COMMENT 'Foreign key linking to compliance.policy. Business justification: Individual deal terms (NIL rights, exclusivity clauses, broadcast integration) must be governed by specific compliance policies (WADA, FCC, GDPR). Sports entertainment compliance teams map contract te',
    `product_category_id` BIGINT COMMENT 'Foreign key linking to merchandise.product_category. Business justification: Sponsorship deal terms contractually specify which merchandise product categories are covered by exclusivity or licensing rights (e.g., apparel rights vs. hard goods). Linking deal_term to product_cat',
    `regulatory_filing_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_filing. Business justification: Specific deal terms generate regulatory filings: NIL athlete rights terms require governing body filings, broadcast integration terms require FCC filings, exclusivity terms may require competition aut',
    `revenue_recognition_schedule_id` BIGINT COMMENT 'Foreign key linking to finance.revenue_recognition_schedule. Business justification: Deal terms define the performance obligations that drive ASC 606 revenue recognition. Finance maps each deal term to a recognition schedule to determine how to spread contract revenue across periods. ',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Deal terms have season-scoped obligations — escalation rates, performance bonus triggers, and GRP delivery commitments are season-bound. Season-level term tracking is required for revenue recognition ',
    `sponsor_id` BIGINT COMMENT 'Reference to the sponsoring organization or brand entity that is party to this deal term. Supports sponsor lifecycle and CRM integration.',
    `activation_deliverable_count` STRING COMMENT 'Total number of distinct brand activation deliverables committed under this deal term (e.g., in-venue signage placements, broadcast integrations, digital content pieces, hospitality events). Drives activation fulfillment tracking.',
    `broadcast_integration_type` STRING COMMENT 'Specifies the type of broadcast integration deliverable included in this deal term. Virtual_led = virtual pitch-side LED branding; on_screen_graphic = branded lower-third or overlay; presenter_mention = verbal sponsor mention by broadcaster; sponsored_segment = branded content segment; halftime_show = halftime entertainment sponsorship; replay_sponsor = branded replay sequence. Null if term_type is not broadcast_integration.. Valid values are `virtual_led|on_screen_graphic|presenter_mention|sponsored_segment|halftime_show|replay_sponsor`',
    `cash_fee_amount` DECIMAL(18,2) COMMENT 'The portion of the total contract fee to be paid in cash by the sponsor. Distinguishes cash from Value-in-Kind (VIK) contributions for revenue recognition and EBITDA reporting purposes.',
    `cpm_rate` DECIMAL(18,2) COMMENT 'The agreed Cost Per Mille (CPM) rate in the contract currency for digital or broadcast advertising inventory delivered under this deal term. CPM represents the cost per 1,000 impressions. Used for digital platform partnership valuation and ROI reporting.',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp recording when this deal term record was first created in the lakehouse Silver Layer. Supports audit trail, data lineage, and SOX compliance requirements.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code in which the total contract fee and all monetary obligations under this deal term are denominated (e.g., USD, GBP, EUR). Required for multi-currency SAP S/4HANA FI integration.. Valid values are `^[A-Z]{3}$`',
    `dispute_resolution_mechanism` STRING COMMENT 'The contractually agreed mechanism for resolving disputes arising under this deal term. Arbitration typically references CAS (Court of Arbitration for Sport) or ICC; litigation refers to national courts; mediation is non-binding; expert_determination applies to technical valuation disputes.. Valid values are `arbitration|litigation|mediation|expert_determination`',
    `effective_end_date` DATE COMMENT 'Calendar date on which this deal term expires or ceases to be binding. Nullable for open-ended or evergreen terms. Drives renewal option evaluation and billing cutoff.',
    `effective_start_date` DATE COMMENT 'Calendar date on which this deal term becomes legally binding and commercially effective. Used for billing schedule generation in SAP S/4HANA SD.',
    `escalation_basis` STRING COMMENT 'The basis on which the escalation rate is calculated. Fixed_rate applies a predetermined percentage; cpi_linked ties escalation to the Consumer Price Index; revenue_linked ties it to the organizations revenue growth; negotiated means the rate is renegotiated at each interval.. Valid values are `fixed_rate|cpi_linked|revenue_linked|negotiated`',
    `escalation_rate_pct` DECIMAL(18,2) COMMENT 'Annual percentage rate by which the contract fee escalates over the term (e.g., 3.00 = 3% per annum). Supports multi-year deal modeling and SAP S/4HANA SD billing plan escalation configuration. Null if no escalation clause applies.',
    `exclusivity_category` STRING COMMENT 'Narrative description of the product or service category in which exclusivity is granted (e.g., Official Automotive Partner — passenger vehicles, Official Financial Services Partner — retail banking). Null if exclusivity_flag is False.',
    `exclusivity_flag` BOOLEAN COMMENT 'Indicates whether this deal term grants the sponsor category exclusivity, preventing the rights holder from entering into competing sponsorship agreements within the same product or service category during the term. True = exclusive; False = non-exclusive.',
    `force_majeure_clause_flag` BOOLEAN COMMENT 'Indicates whether this deal term contains a force majeure clause that suspends or modifies obligations in the event of extraordinary circumstances beyond either partys control (e.g., pandemic, natural disaster, government prohibition of events). True = force majeure clause present.',
    `governing_law_jurisdiction` STRING COMMENT 'Three-letter ISO 3166-1 Alpha-3 country code identifying the legal jurisdiction whose laws govern this deal term in the event of a dispute (e.g., USA, GBR, CHE). Determines applicable regulatory frameworks including GDPR, CCPA, and local contract law.. Valid values are `^[A-Z]{3}$`',
    `grp_delivery_commitment` DECIMAL(18,2) COMMENT 'The contractually committed Gross Rating Point (GRP) delivery target for broadcast or media placements associated with this deal term. GRP measures the total advertising weight delivered to the target audience. Used for ROI tracking and make-good calculations.',
    `invoice_milestone_count` STRING COMMENT 'Total number of billing milestones or invoice installments defined under this deal terms payment schedule. Used to validate completeness of the SAP S/4HANA SD billing plan and track invoicing progress.',
    `ip_rights_granted_flag` BOOLEAN COMMENT 'Indicates whether this deal term grants the sponsor rights to use the organizations Intellectual Property (IP) — including logos, trademarks, athlete likenesses, and league marks — in their own marketing and advertising. True = IP rights granted; False = no IP rights granted. Relevant to NIL (Name, Image, and Likeness) compliance.',
    `jersey_placement_location` STRING COMMENT 'Specifies the physical location on the team kit where the sponsors branding is placed under a jersey sponsorship deal term. Null if term_type is not jersey_sponsorship. [ENUM-REF-CANDIDATE: front_chest|back_upper|sleeve_left|sleeve_right|collar|shorts|training_kit|goalkeeper_kit — promote to reference product]',
    `kill_clause_flag` BOOLEAN COMMENT 'Indicates whether this deal term contains a kill clause (early termination right) that either party may invoke upon breach of defined thresholds. True = kill clause present; False = no kill clause.',
    `kill_clause_threshold` STRING COMMENT 'Narrative description of the specific condition or metric threshold that triggers the kill clause (e.g., Sponsor brand NPS falls below 20, Broadcast audience drops below 500,000 for 2 consecutive events, Regulatory sanction imposed on either party). Null if kill_clause_flag is False.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'System timestamp recording when this deal term record was most recently modified in the lakehouse Silver Layer. Supports change data capture, audit trail, and SOX compliance.',
    `late_payment_penalty_rate_pct` DECIMAL(18,2) COMMENT 'Annual percentage rate applied to overdue sponsor payments as a contractual late payment penalty (e.g., 1.50 = 1.5% per annum on outstanding balance). Null if no late payment penalty clause exists. Used in SAP S/4HANA FI dunning configuration.',
    `naming_rights_asset` STRING COMMENT 'Description of the specific asset (venue, stadium, arena, event, competition, or league) for which naming rights are granted under this deal term (e.g., Main Stadium — Exterior and Interior Branding, Annual Championship Series). Null if term_type is not naming_rights.',
    `nil_athlete_rights_flag` BOOLEAN COMMENT 'Indicates whether this deal term specifically includes Name, Image, and Likeness (NIL) rights for one or more individual athletes, allowing the sponsor to use athlete identity in commercial activations. True = NIL rights included; False = no individual athlete NIL rights.',
    `payment_schedule_type` STRING COMMENT 'Defines the cadence or trigger basis for sponsor payment obligations under this deal term. Annual, quarterly, and monthly are calendar-based; milestone is event-triggered (e.g., season opener, playoff appearance); upfront is a single lump-sum at signing; deferred is back-loaded. Drives SAP S/4HANA SD billing plan configuration. [ENUM-REF-CANDIDATE: annual|semi_annual|quarterly|monthly|milestone|upfront|deferred — 7 candidates stripped; promote to reference product]',
    `performance_bonus_amount` DECIMAL(18,2) COMMENT 'Additional monetary amount payable by the sponsor upon achievement of defined performance milestones (e.g., team reaching playoffs, broadcast audience exceeding GRP threshold, NPS target met). Null if no performance bonus clause exists.',
    `performance_bonus_trigger` STRING COMMENT 'Narrative description of the specific performance condition(s) that must be met to trigger the performance bonus payment (e.g., Team qualifies for championship final, Broadcast CPM exceeds $25 for 3 consecutive quarters, GRP delivery exceeds 500 in target demographic).',
    `renewal_notice_days` STRING COMMENT 'Number of calendar days prior to the effective end date by which the sponsor or rights holder must provide written notice to exercise the renewal option. Drives automated renewal alert workflows in Salesforce CRM.',
    `renewal_option_flag` BOOLEAN COMMENT 'Indicates whether this deal term includes a contractual renewal option that the sponsor or rights holder may exercise before expiry. True = renewal option exists; False = no renewal option.',
    `renewal_option_periods` STRING COMMENT 'Number of additional renewal periods the sponsor may exercise under the renewal option clause (e.g., 2 = two additional one-year terms). Null if renewal_option_flag is False.',
    `rofr_flag` BOOLEAN COMMENT 'Indicates whether the sponsor holds a Right of First Refusal (ROFR) on the renewal of this deal term, giving them priority to match any competing offer before the rights are offered to a third party. True = ROFR granted; False = no ROFR.',
    `sap_billing_plan_type` STRING COMMENT 'The SAP S/4HANA SD billing plan type code assigned to this deal term, controlling how and when invoices are generated (e.g., 01 for milestone billing, 02 for periodic billing). Directly maps to SAP billing plan configuration.',
    `sap_contract_number` STRING COMMENT 'The SAP S/4HANA SD sales contract document number associated with this deal term, used for billing plan integration, invoice generation, and revenue recognition. Enables traceability between the lakehouse Silver Layer and the ERP system of record.',
    `signed_date` DATE COMMENT 'The calendar date on which this deal term was formally executed and signed by all parties. Represents the principal business event timestamp for the contractual commitment. Used for SOX revenue recognition cutoff and audit trail.',
    `term_reference_number` STRING COMMENT 'Externally-known alphanumeric reference code for this deal term record, used in SAP S/4HANA SD billing and contract correspondence. Format: <ORG_CODE>-DT-<SEQUENCE>.. Valid values are `^[A-Z]{2,6}-DT-[0-9]{4,10}$`',
    `term_status` STRING COMMENT 'Current lifecycle state of the deal term. Draft indicates terms under negotiation; active indicates binding and in-force; suspended indicates temporarily paused (e.g., force majeure); terminated indicates early exit via kill clause; expired indicates natural end-of-term; pending_renewal indicates renewal option under evaluation.. Valid values are `draft|active|suspended|terminated|expired|pending_renewal`',
    `term_type` STRING COMMENT 'Classification of the deal term by its commercial nature. Financial covers cash payment obligations; activation covers brand activation deliverables; naming_rights covers venue or event naming; broadcast_integration covers in-broadcast placements; digital_platform covers OTT/DTC digital integrations; jersey_sponsorship covers kit branding rights. [ENUM-REF-CANDIDATE: financial|activation|naming_rights|broadcast_integration|digital_platform|jersey_sponsorship|merchandise_licensing|hospitality — promote to reference product]. Valid values are `financial|activation|naming_rights|broadcast_integration|digital_platform|jersey_sponsorship`',
    `total_contract_fee` DECIMAL(18,2) COMMENT 'Gross total monetary value of this deal term over its full effective period, expressed in the contract currency. Represents the face value of the sponsorship obligation before any escalation, bonus, or VIK adjustments. Key input for EBITDA and ARR reporting.',
    `vik_amount` DECIMAL(18,2) COMMENT 'The portion of the total contract fee fulfilled through non-cash Value-in-Kind (VIK) contributions such as goods, services, media inventory, or hospitality provided by the sponsor. Tracked separately from cash for accounting and ROI analysis.',
    `vik_description` STRING COMMENT 'Narrative description of the non-cash Value-in-Kind (VIK) goods or services provided by the sponsor as part of their contractual obligation (e.g., Official airline partner — 500 business class flights per season, Official vehicle fleet — 50 SUVs for event logistics).',
    CONSTRAINT pk_deal_term PRIMARY KEY(`deal_term_id`)
) COMMENT 'Detailed contractual terms and financial obligations associated with a sponsorship deal. Captures payment schedule type (annual, quarterly, milestone), total fee, cash vs. value-in-kind (VIK) split, escalation clauses, performance bonuses, kill-clause thresholds, renewal options, right-of-first-refusal flags, and governing law jurisdiction. Supports SAP S/4HANA SD billing integration for invoicing milestones.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`sponsorship`.`activation` (
    `activation_id` BIGINT COMMENT 'Unique surrogate identifier for each brand activation deliverable record within a sponsorship deal.',
    `access_zone_id` BIGINT COMMENT 'Foreign key linking to security.access_zone. Business justification: Sponsor activations are physically located in specific security access zones (concourse, field level, broadcast zone). Security planners need this link to staff activation zones correctly, enforce cap',
    `fixture_id` BIGINT COMMENT 'Reference to the specific sporting or entertainment event at which this activation is scheduled or was delivered.',
    `activation_fixture_id` BIGINT COMMENT 'Reference to the specific sporting or entertainment event at which this activation is scheduled or was delivered.',
    `athlete_profile_id` BIGINT COMMENT 'Foreign key linking to athlete.athlete_profile. Business justification: Athlete activation fulfillment process: sponsorship activations frequently feature specific athletes (appearances, autograph sessions, athlete-branded in-venue signage). Activation teams must track wh',
    `betting_market_id` BIGINT COMMENT 'Foreign key linking to gaming.betting_market. Business justification: Betting-integrated sponsorship activations (e.g., Bet Builder presented by [Sponsor]) run on specific betting markets. Activation fulfillment and proof-of-performance reporting require knowing which',
    `channel_id` BIGINT COMMENT 'Foreign key linking to broadcast.channel. Business justification: Sponsorship activations (virtual overlays, branded segments, ad insertions) are delivered on specific broadcast channels. Channel attributes (ad_insertion_enabled, platform_type, territory) govern act',
    `broadcast_schedule_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_schedule. Business justification: Activations with broadcast channel delivery require a link to the authoritative broadcast schedule record. Replaces denormalized broadcast_network and broadcast_window columns. Enables operational tra',
    `budget_id` BIGINT COMMENT 'Foreign key linking to finance.budget. Business justification: Activation spend (production, staffing, digital) is tracked against dedicated activation budget lines. Sports sponsorship teams manage activation budgets separately from deal budgets; linking activati',
    `contest_id` BIGINT COMMENT 'Foreign key linking to gaming.contest. Business justification: Sponsorship activations include branded DFS contests (e.g., Enter the [Sponsor] Fantasy Challenge). Activation fulfillment tracking for DFS-integrated sponsorships requires a direct reference to the',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Activation execution incurs costs (production, staffing, materials, venue setup) tracked against cost centers for budget variance analysis. Finance requires cost center assignment on activations for a',
    `asset_id` BIGINT COMMENT 'Foreign key linking to content.asset. Business justification: Activation managers must link each activation to its approved creative asset in the DAM for brand safety review, FCC disclosure verification, and proof-of-performance audits. No existing FK covers act',
    `deal_id` BIGINT COMMENT 'Reference to the parent sponsorship deal under which this activation deliverable was committed.',
    `deal_term_id` BIGINT COMMENT 'Foreign key linking to sponsorship.deal_term. Business justification: Sponsorship activations are deliverables committed within a deal, and deal_term is the specific contractual instrument that defines the activation deliverables (activation_deliverable_count, broadcast',
    `segment_id` BIGINT COMMENT 'Foreign key linking to fan.segment. Business justification: Sponsorship activations are planned and executed against specific fan segments (e.g., target 18-34 season ticket holders). Linking activation to fan.segment enables segment-level activation performa',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Sponsorship activations are frequently franchise-specific — jersey patch activations, in-arena signage, and team-branded digital overlays belong to a specific franchise. Franchise-level activation ful',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Activations are executed within a specific league season (e.g., Season 2024-25 jersey activation). Season-level activation fulfillment reporting and make-good tracking require a structured season FK; ',
    `media_rights_deal_id` BIGINT COMMENT 'Foreign key linking to broadcast.media_rights_deal. Business justification: Broadcast-integrated sponsorship activations (virtual overlays, branded segments) must be validated against the governing media rights deal to confirm territory compliance, sublicensing permissions, a',
    `naming_right_id` BIGINT COMMENT 'Foreign key linking to sponsorship.naming_right. Business justification: sponsorship_activation has a naming_rights: BOOLEAN flag indicating when an activation is of the naming rights type. When naming_rights=true, the activation should reference the specific naming_right ',
    `nil_agreement_id` BIGINT COMMENT 'Foreign key linking to athlete.nil_agreement. Business justification: NIL rights usage compliance: activations deploying athlete name, image, or likeness must reference the governing NIL agreement to confirm broadcast_usage_rights, digital_usage_rights, and in_venue_usa',
    `operator_id` BIGINT COMMENT 'Foreign key linking to gaming.operator. Business justification: Activations executed for gaming operators require operator reference for regulatory compliance — responsible gaming disclosures, jurisdiction eligibility verification, and proof-of-performance reporti',
    `platform_channel_id` BIGINT COMMENT 'Foreign key linking to content.platform_channel. Business justification: Activation delivery reporting requires knowing which platform channel (OTT, social, broadcast digital) an activation ran on. The existing `channel` text field is denormalized; linking to platform_chan',
    `policy_id` BIGINT COMMENT 'Foreign key linking to compliance.policy. Business justification: Activations must comply with specific policies (FCC disclosure, GDPR consent, WADA sponsor category restrictions). sponsorship_activation has fcc_disclosure_required and fcc_disclosure_text as plain a',
    `regulatory_filing_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_filing. Business justification: Activations with fcc_disclosure_required must reference the actual FCC regulatory filing that documents the disclosure. Compliance and operations teams need this link to verify that every activation r',
    `sponsor_id` BIGINT COMMENT 'Reference to the sponsoring brand or organisation responsible for this activation.',
    `venue_id` BIGINT COMMENT 'Reference to the venue where the in-venue or naming-rights activation is placed.',
    `activation_code` STRING COMMENT 'Externally-known alphanumeric reference code for this activation deliverable, used in deal documentation, invoicing, and partner communications.. Valid values are `^ACT-[A-Z0-9]{4,12}$`',
    `activation_name` STRING COMMENT 'Human-readable name or title of the brand activation deliverable (e.g., Halftime Show Title Sponsor Billboard, Jersey Sleeve Patch — Season 2025).',
    `activation_type` STRING COMMENT 'The specific commercial activation format applied to this deals coverage of this betting market — e.g., branded odds feed, broadcast mention during live in-play, or co-branded market name. Belongs to the activation record, not to the deal or market independently.',
    `actual_delivery_date` DATE COMMENT 'Date on which the activation was confirmed as fully delivered. Used for fulfillment reconciliation and sponsor reporting.',
    `airtime_seconds` STRING COMMENT 'Contracted or delivered airtime duration in seconds for broadcast and audio activations (e.g., 30-second billboard, 15-second PA announcement).',
    `contracted_impressions` BIGINT COMMENT 'The number of guaranteed impressions committed for this specific deal-market combination. Distinct from the deal-level impression_commitment on the deal master, which aggregates across all market activations.',
    `contracted_quantity` STRING COMMENT 'Number of activation units committed in the sponsorship deal (e.g., number of broadcast spots, number of in-venue signage placements, number of social posts).',
    `contracted_value` DECIMAL(18,2) COMMENT 'Monetary value attributed to this individual activation deliverable as allocated from the parent sponsorship deal. Used for ROI tracking and revenue recognition.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this activation record was first created in the system.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the contracted activation value (e.g., USD, GBP, EUR).. Valid values are `^[A-Z]{3}$`',
    `delivered_quantity` STRING COMMENT 'Actual number of activation units delivered to date. Compared against contracted_quantity to determine fulfillment rate and identify shortfalls.',
    `drm_compliant` BOOLEAN COMMENT 'Indicates whether the digital activation asset has been verified as compliant with DRM (Digital Rights Management) policies, including IP licensing and content protection requirements.',
    `effective_end_date` DATE COMMENT 'The date on which this deals activation coverage of this specific betting market category expires. May differ from the parent deals end_date if market coverage is phased or terminated early.',
    `effective_start_date` DATE COMMENT 'The date on which this deals activation coverage of this specific betting market category becomes effective. May differ from the parent deals start_date if market coverage is phased.',
    `fcc_disclosure_required` BOOLEAN COMMENT 'Indicates whether this broadcast activation requires a sponsorship identification disclosure per FCC regulations (47 CFR §317 and §507). Mandatory for paid broadcast integrations.',
    `fcc_disclosure_text` STRING COMMENT 'Exact on-air or on-screen disclosure text required by FCC regulations for this broadcast activation (e.g., Paid for by [Sponsor Name]). Null if FCC disclosure is not required.',
    `fulfillment_status` STRING COMMENT 'Current lifecycle state of the activation deliverable tracking what was promised versus what has been delivered.. Valid values are `draft|scheduled|in_progress|fulfilled|partially_fulfilled|cancelled`',
    `grp_contracted` DECIMAL(18,2) COMMENT 'Gross Rating Points committed in the sponsorship deal for broadcast activations. GRP = Reach % × Frequency, used for broadcast media valuation.',
    `grp_delivered` DECIMAL(18,2) COMMENT 'Actual Gross Rating Points delivered for broadcast activations as measured post-airing. Used for sponsor ROI reporting and make-good calculations.',
    `impressions_contracted` BIGINT COMMENT 'Number of audience impressions (CPM basis) committed in the sponsorship deal for this activation. Used for GRP/CPM performance measurement.',
    `impressions_delivered` BIGINT COMMENT 'Actual audience impressions delivered for this activation as measured by third-party or internal analytics. Compared against contracted impressions for ROI reporting.',
    `jersey_placement_position` STRING COMMENT 'Specific position on the athlete kit where the sponsor brand appears. Applicable only for jersey/kit channel activations.. Valid values are `sleeve|patch|collar|chest|back|shorts`',
    `kit_manufacturer` STRING COMMENT 'Name of the official kit/apparel manufacturer (e.g., Nike, Adidas, Under Armour) relevant for jersey placement activations, as kit manufacturer approval may be required per CBA or league rules.',
    `market_category_exclusivity` STRING COMMENT 'Indicates whether the sponsoring brand holds exclusive rights within this betting market category under this deal. Cannot reside on deal (which spans many categories) nor on betting_market (which is a shared catalog definition).',
    `naming_rights` BOOLEAN COMMENT 'Indicates whether this activation constitutes or is associated with a venue or event naming rights arrangement.',
    `notes` STRING COMMENT 'Free-text field for operational notes, special instructions, make-good arrangements, or exceptions related to this activation deliverable.',
    `placement_dimensions` STRING COMMENT 'Physical or pixel dimensions of the activation placement (e.g., 3m x 1m, 728x90px, 30s airtime). Supports fulfillment verification and creative asset compliance.',
    `placement_location` STRING COMMENT 'Specific physical or digital location of the activation (e.g., North End Zone LED Board Row 1, Left Sleeve, Pre-Roll Slot — ESPN OTT, Homepage Banner Position 1).',
    `proof_of_performance_url` STRING COMMENT 'URL or DAM (Digital Asset Management) reference link to the proof-of-performance documentation (photos, broadcast clips, screenshots) confirming activation delivery.',
    `responsible_team` STRING COMMENT 'Internal business team or department accountable for delivering this activation (e.g., Broadcast Partnerships, In-Venue Operations, Digital Marketing, Merchandise & Licensing).',
    `scheduled_end_date` DATE COMMENT 'Planned date on which the activation deliverable is scheduled to conclude (e.g., last game of season, campaign end date).',
    `scheduled_start_date` DATE COMMENT 'Planned date on which the activation deliverable is scheduled to begin (e.g., first game of season, campaign launch date).',
    `sponsor_approval_status` STRING COMMENT 'Status of the sponsors review and approval of the activation creative assets and placement specifications prior to delivery.. Valid values are `pending|approved|rejected|revision_requested`',
    `sponsor_approved_timestamp` TIMESTAMP COMMENT 'Date and time when the sponsor formally approved the activation creative and placement specifications.',
    `sponsorship_activation_category` STRING COMMENT 'High-level classification of the activation type. [ENUM-REF-CANDIDATE: in_venue_signage|jersey_placement|broadcast_billboard|virtual_led_overlay|sponsored_segment|branded_replay|digital_banner|social_media_post|experiential|naming_rights_display|pa_announcement|led_perimeter_board|halftime_show_integration|broadcast_integration — promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when this activation record was most recently modified.',
    `virtual_overlay` BOOLEAN COMMENT 'Indicates whether this activation uses virtual LED overlay technology (digitally inserted signage visible only in broadcast, not physically present in venue).',
    `visibility_tier` STRING COMMENT 'Commercial tier indicating the prominence and audience reach of the placement (Premium = highest visibility/CPM, Standard, Value = lowest).. Valid values are `premium|standard|value`',
    CONSTRAINT pk_activation PRIMARY KEY(`activation_id`)
) COMMENT 'Master record for individual brand activation deliverables committed within a sponsorship deal. Captures activation name, activation category (in-venue signage, jersey patch/sleeve/collar placement, broadcast billboard, virtual LED overlay, sponsored segment, branded replay, digital banner, social media post, experiential activation, naming rights display, PA announcement, LED perimeter board, halftime show integration, broadcast integration type with network/OTT platform association, airtime and duration), placement specifications (location, dimensions, visibility tier, kit manufacturer for jersey placements), scheduled and actual delivery dates, fulfillment status, responsible team, broadcast window, FCC/regulatory disclosure requirements, DRM compliance flags, and associated event. Core entity for tracking what was promised vs. delivered across all activation channels including broadcast integrations, jersey placements, and digital activations.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`sponsorship`.`activation_fulfillment` (
    `activation_fulfillment_id` BIGINT COMMENT 'Unique surrogate identifier for each brand activation fulfillment record in the sponsorship domain. Primary key for this transactional entity.',
    `ar_invoice_id` BIGINT COMMENT 'Foreign key linking to finance.ar_invoice. Business justification: Proof-of-performance fulfillment directly triggers AR invoice release in sponsorship billing. Finance teams require the fulfillment-to-invoice link to enforce billing-on-delivery terms, resolve sponso',
    `audience_rating_id` BIGINT COMMENT 'Foreign key linking to broadcast.audience_rating. Business justification: Activation fulfillment tracks grp_achieved, cpm_realized, and audience_reach. These values are sourced from audience_rating measurement records. Linking provides the measurement record that validates ',
    `broadcast_schedule_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_schedule. Business justification: Activation fulfillment proof-of-play requires the authoritative broadcast log. Linking to broadcast_schedule provides the scheduled and actual air timestamps for verification. Replaces denormalized br',
    `contest_id` BIGINT COMMENT 'Foreign key linking to gaming.contest. Business justification: Fulfillment records for contest-sponsored activations (e.g., title-sponsored DFS contests) must reference the specific contest to verify proof-of-performance and confirm contracted deliverables were m',
    `asset_id` BIGINT COMMENT 'Foreign key linking to content.asset. Business justification: Fulfillment verification requires linking the delivered creative asset to the fulfillment record for brand safety audit and DRM compliance. creative_asset_reference is a plain-text denormalization of ',
    `fiscal_period_id` BIGINT COMMENT 'Foreign key linking to finance.fiscal_period. Business justification: Fulfillment records must be period-stamped for revenue recognition cutoff and accrual accounting at period-close. Finance teams require fiscal period assignment on fulfillment to determine which perio',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Fulfillment proof-of-performance is franchise-specific — jersey patch airtime, in-arena impression delivery, and broadcast mention counts are measured per franchise. Franchise-level fulfillment report',
    `inventory_allocation_id` BIGINT COMMENT 'Foreign key linking to sponsorship.inventory_allocation. Business justification: activation_fulfillment records the actual proof-of-performance execution for a brand activation. inventory_allocation is the transactional record linking specific ad inventory units to deals and activ',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Fulfillment records have plain-text season and league_or_property columns (denormalization signals). Season-level fulfillment reporting, make-good tracking, and sponsor billing reconciliation requ',
    `live_feed_id` BIGINT COMMENT 'Foreign key linking to broadcast.live_feed. Business justification: Proof-of-play for broadcast sponsorship activations (proof_of_play_reference, broadcast_log_timestamp) must reference the specific live feed on which the activation aired. Required for sponsor invoici',
    `fixture_id` BIGINT COMMENT 'Reference to the sports or entertainment event during which this activation was fulfilled (e.g., game, concert, match). Nullable for non-event-tied digital or broadcast activations.',
    `activation_id` BIGINT COMMENT 'Reference to the parent brand activation deliverable that this fulfillment record is executing against. Links fulfillment to the contracted activation obligation.',
    `regulatory_filing_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_filing. Business justification: Broadcast activation fulfillments generate FCC proof-of-performance filings and governing body disclosure filings. activation_fulfillment has proof_of_play_reference and brand_safety_compliant as plai',
    `revenue_recognition_schedule_id` BIGINT COMMENT 'Foreign key linking to finance.revenue_recognition_schedule. Business justification: Fulfillment events trigger revenue recognition — when a contracted activation is delivered, the associated deferred revenue is released. Finance links fulfillment records to recognition schedules to t',
    `sponsor_id` BIGINT COMMENT 'Reference to the sponsoring brand or corporate partner whose contracted activation is being fulfilled. Used for sponsor-level ROI aggregation and renewal reporting.',
    `venue_id` BIGINT COMMENT 'Reference to the venue where the in-venue activation was executed. Nullable for broadcast, digital, or social channel fulfillments.',
    `activation_type` STRING COMMENT 'Classification of the brand activation format being fulfilled. Covers the full spectrum of sponsorship inventory types including naming rights, jersey sponsorships, broadcast integrations, digital banners, social posts, in-venue signage, VIP hospitality, and product placements. [ENUM-REF-CANDIDATE: naming_rights|jersey_sponsorship|broadcast_integration|digital_banner|social_post|in_venue_signage|vip_hospitality|product_placement|stadium_wrap|scoreboard — promote to reference product]',
    `audience_demographic_target` STRING COMMENT 'The contracted target demographic segment for this activation (e.g., Adults 18-49, Males 25-54, Households with income >$75K). Used to assess whether delivered impressions matched the sponsors intended audience profile.',
    `audience_reach` BIGINT COMMENT 'Estimated number of unique individuals reached by this activation fulfillment, distinct from total impressions which may count repeat exposures. Used alongside GRP to calculate frequency and assess campaign effectiveness.',
    `brand_safety_compliant` BOOLEAN COMMENT 'Indicates whether the activation fulfillment met all brand safety requirements as defined in the sponsorship contract (e.g., no adjacency to prohibited content, correct placement context). Critical for broadcast and digital channel fulfillments.',
    `broadcast_log_timestamp` TIMESTAMP COMMENT 'The precise timestamp recorded in the broadcast transmission log (Dalet Galaxy) confirming the exact air time of the sponsored content or advertisement. Used for broadcast fulfillment verification and FCC compliance documentation.',
    `cpm_contracted` DECIMAL(18,2) COMMENT 'The Cost Per Mille (CPM) rate contractually agreed with the sponsor, representing the cost per 1,000 impressions. Confidential commercial term used to calculate the monetary value of delivered impressions and assess ROI.',
    `cpm_realized` DECIMAL(18,2) COMMENT 'The effective Cost Per Mille (CPM) achieved based on actual impressions delivered versus the contracted value. Calculated as (contract_value / impressions_delivered) * 1000. Used in ROI reporting and renewal pricing benchmarking.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this activation fulfillment record was first created in the system. Audit trail field supporting data lineage, SOX compliance, and GDPR data processing records.',
    `duration_seconds` STRING COMMENT 'Duration in seconds for which the activation was displayed or broadcast. Applicable to broadcast spots, digital display ads, LED board rotations, and video pre-rolls. Used to verify compliance with contracted exposure time.',
    `fulfillment_channel` STRING COMMENT 'The media or physical channel through which the brand activation was delivered to the audience. Broadcast covers linear TV/radio; OTT covers streaming platforms; digital covers web/app; social covers social media platforms; in_venue covers physical stadium/arena placements. [ENUM-REF-CANDIDATE: broadcast|in_venue|digital|social|ott|print|podcast|out_of_home — promote to reference product if additional channels are added]. Valid values are `broadcast|in_venue|digital|social|ott|print`',
    `fulfillment_date` DATE COMMENT 'Calendar date on which the brand activation was executed and delivered to the sponsor. Used as the principal business event date for ROI reporting and proof-of-performance documentation.',
    `fulfillment_quality_rating` DECIMAL(18,2) COMMENT 'Numeric quality score (1.0 to 5.0) assigned to this activation fulfillment based on placement prominence, brand safety compliance, creative execution fidelity, and audience alignment. Used in sponsor satisfaction reporting and renewal scoring.',
    `fulfillment_reference_number` STRING COMMENT 'Externally-known alphanumeric business identifier for this fulfillment record, used in proof-of-performance reports, sponsor invoices, and renewal negotiations. Format: ACT-FUL-YYYYMMDD-XXXX.. Valid values are `^ACT-FUL-[0-9]{8}-[A-Z0-9]{4}$`',
    `fulfillment_status` STRING COMMENT 'Current lifecycle state of the activation fulfillment record. Partial indicates some but not all contracted deliverables were met. Shortfall indicates a measurable gap against contracted impressions or GRP targets. Drives renewal negotiation and make-good obligations.. Valid values are `pending|fulfilled|partial|shortfall|disputed|cancelled`',
    `fulfillment_timestamp` TIMESTAMP COMMENT 'Precise date and time at which the activation was executed, including timezone offset. Used for broadcast log reconciliation, OTT stream timestamping, and in-venue display scheduling verification.',
    `fulfillment_value_usd` DECIMAL(18,2) COMMENT 'The monetary value attributed to this specific activation fulfillment in US Dollars, derived from the contracted rate and delivered impressions. Used for revenue recognition, sponsor invoicing, and EBITDA reporting under SAP S/4HANA FI/CO.',
    `grp_achieved` DECIMAL(18,2) COMMENT 'Actual Gross Rating Points (GRP) delivered for this activation fulfillment as reported by the audience measurement provider. Compared against grp_contracted to determine fulfillment compliance and trigger make-good obligations.',
    `grp_contracted` DECIMAL(18,2) COMMENT 'The Gross Rating Points (GRP) target contractually committed for this activation, representing reach multiplied by frequency against the target demographic. Used as the broadcast and media benchmark for fulfillment assessment.',
    `impressions_contracted` BIGINT COMMENT 'The number of audience impressions contractually obligated for this activation as specified in the sponsorship deal terms. Serves as the benchmark against which delivered impressions are measured for shortfall and make-good calculations.',
    `impressions_delivered` BIGINT COMMENT 'Actual number of audience impressions delivered for this activation fulfillment as measured by the relevant audience measurement system (Nielsen, Comscore, or venue attendance data). Core metric for CPM calculation and ROI reporting.',
    `makegood_required` BOOLEAN COMMENT 'Indicates whether a make-good (compensatory activation) is required due to under-delivery against contracted impressions or GRP targets. True triggers a make-good workflow in Salesforce CRM for scheduling a replacement activation.',
    `placement_location` STRING COMMENT 'Specific physical or digital location of the activation placement (e.g., North End Zone LED Board, Halftime Show Stage Banner, Homepage Hero Banner, Pre-Roll Video Slot 1). Provides granular proof-of-placement detail for sponsor reporting.',
    `proof_of_play_reference` STRING COMMENT 'Unique identifier or URI pointing to the proof-of-performance artifact (e.g., screenshot filename, broadcast log timestamp key, photo asset ID in DAM, or OTT stream clip reference). Used to substantiate fulfillment claims in sponsor reporting and dispute resolution.',
    `proof_type` STRING COMMENT 'Classification of the proof-of-performance artifact submitted for this fulfillment. Determines the verification workflow and the level of evidentiary weight assigned during sponsor audit or dispute resolution.. Valid values are `screenshot|broadcast_log|photo|video_clip|affidavit|third_party_report`',
    `shortfall_impressions` BIGINT COMMENT 'The gap between contracted impressions and delivered impressions (impressions_contracted minus impressions_delivered). Positive values indicate under-delivery triggering make-good obligations. Zero or negative values indicate full or over-delivery.',
    `shortfall_notes` STRING COMMENT 'Free-text explanation of any under-delivery or fulfillment gap, including root cause (e.g., event cancellation, broadcast preemption, technical failure, weather). Used in sponsor communications, make-good planning, and renewal negotiations.',
    `sponsor_acknowledged` BOOLEAN COMMENT 'Indicates whether the sponsor has formally acknowledged and accepted this fulfillment record as proof-of-performance. True enables revenue recognition and closes the fulfillment obligation in SAP S/4HANA.',
    `sponsor_acknowledgement_date` DATE COMMENT 'Date on which the sponsor formally acknowledged and accepted the fulfillment proof-of-performance. Nullable until acknowledgement is received. Used as the trigger date for revenue recognition and invoice generation.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this activation fulfillment record. Supports audit trail requirements, change tracking, and Silver Layer incremental processing in the Databricks Lakehouse.',
    `verification_date` DATE COMMENT 'Date on which the fulfillment record was formally verified and approved by the responsible party or third-party measurement provider. Marks the transition from pending to fulfilled or shortfall status.',
    CONSTRAINT pk_activation_fulfillment PRIMARY KEY(`activation_fulfillment_id`)
) COMMENT 'Transactional record capturing the actual execution and proof-of-performance for each brand activation. Records fulfillment date, fulfillment channel (broadcast, in-venue, digital, social, OTT), proof-of-play reference (screenshot, broadcast log timestamp, photo), impressions delivered, GRP achieved, CPM realized, fulfillment quality rating, and any shortfall notes. Feeds ROI reporting and renewal negotiations.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`sponsorship`.`naming_right` (
    `naming_right_id` BIGINT COMMENT 'Unique surrogate identifier for the naming rights agreement record in the Sports Entertainment data platform.',
    `budget_id` BIGINT COMMENT 'Foreign key linking to finance.budget. Business justification: Naming rights agreements have activation_budget_amount that must be tracked against a dedicated finance budget line. Major naming rights deals (stadium, arena) have multi-year budget allocations; link',
    `deal_id` BIGINT COMMENT 'Reference to the parent sponsorship deal or master partnership agreement under which this naming rights component is structured. Links to the sponsorship deal master record in Salesforce CRM.',
    `facility_id` BIGINT COMMENT 'Foreign key linking to venue.facility. Business justification: Naming rights agreements are granted for a specific physical facility (e.g., Acme Arena). naming_right.venue_id identifies the venue but not the specific facility within a multi-facility campus. Con',
    `fixed_asset_id` BIGINT COMMENT 'Foreign key linking to finance.fixed_asset. Business justification: Naming rights agreements are capitalized as intangible assets on the balance sheet (the right to use the venue name). Finance tracks these as fixed/intangible assets with depreciation schedules. A spo',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Naming rights agreements frequently cover franchise-owned assets — practice facilities, team-branded arenas, and franchise digital properties. Franchise attribution is required for asset valuation, SO',
    `governing_body_id` BIGINT COMMENT 'Foreign key linking to compliance.governing_body. Business justification: Naming rights must be approved by the relevant governing body (league, local sports authority). Linking naming_right to governing_body enables compliance teams to track which authority approved the ag',
    `jurisdiction_id` BIGINT COMMENT 'Foreign key linking to gaming.jurisdiction. Business justification: Naming rights agreements for venues in gaming-regulated markets must comply with jurisdiction-specific advertising restrictions. Compliance officers verify that gaming brand naming rights are permissi',
    `league_id` BIGINT COMMENT 'Foreign key linking to league.league. Business justification: Naming rights agreements for venues used by league franchises require league approval and compliance with league branding standards. League-level naming rights portfolio management and approval workfl',
    `media_rights_deal_id` BIGINT COMMENT 'Foreign key linking to broadcast.media_rights_deal. Business justification: Naming rights agreements include broadcast_mention_count_min and broadcast_mention_requirement obligations. The governing media rights deal defines which territories and broadcast windows those mentio',
    `operator_id` BIGINT COMMENT 'Foreign key linking to gaming.operator. Business justification: Naming rights held by gaming operators (e.g., BetMGM Arena, Caesars Superdome) require direct operator reference for license validation, regulatory filing, and renewal compliance. This is a standa',
    `platform_channel_id` BIGINT COMMENT 'Foreign key linking to content.platform_channel. Business justification: Digital naming rights (e.g., Sponsor X App, Sponsor X Streaming Hub) apply to specific platform channels. Linking naming_right to platform_channel supports digital naming rights management, broadc',
    `property_id` BIGINT COMMENT 'Foreign key linking to sponsorship.property. Business justification: A naming right agreement is fundamentally tied to a specific property (stadium, arena, field, etc.). The naming_right table has named_asset_name and named_asset_type as free-text attributes, but the p',
    `regulatory_filing_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_filing. Business justification: Naming rights agreements require regulatory filings with league governing bodies and local authorities for venue name changes. The naming_right has sox_reportable_flag and nil_compliance_flag but no F',
    `revenue_recognition_schedule_id` BIGINT COMMENT 'Foreign key linking to finance.revenue_recognition_schedule. Business justification: Naming rights agreements are multi-year contracts requiring ASC 606 treatment — fees must be recognized over the contract term as the naming obligation is satisfied. Finance maps each naming rights ag',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Naming rights agreements have season-specific fee escalations, renewal option deadlines, and broadcast mention commitments. Season-level naming rights tracking supports annual revenue recognition, ren',
    `sponsor_id` BIGINT COMMENT 'Reference to the sponsoring organisation (naming rights holder) that holds the brand rights to the named asset. Links to the sponsor master record managed in Salesforce CRM.',
    `venue_id` BIGINT COMMENT 'Reference to the venue or property asset that is the subject of the naming rights agreement. Links to the venue master record in the Venue domain. Nullable when the named asset is a non-venue property (trophy, division, award).',
    `activation_budget_amount` DECIMAL(18,2) COMMENT 'Total budget allocated by the sponsor for brand activation activities associated with the naming rights agreement (events, promotions, fan engagement, digital campaigns). Tracked in SAP S/4HANA CO.',
    `agreement_number` STRING COMMENT 'Externally-known contract or deal reference number assigned by the commercial/legal team and used in Salesforce CRM and SAP S/4HANA SD module to uniquely identify this naming rights agreement across systems.',
    `agreement_status` STRING COMMENT 'Current lifecycle state of the naming rights agreement. Drives operational workflows including signage activation, broadcast mention compliance, and renewal outreach. Valid values: draft, active, suspended, expired, terminated, pending_renewal.. Valid values are `draft|active|suspended|expired|terminated|pending_renewal`',
    `agreement_type` STRING COMMENT 'Classification of the named asset category covered by this agreement. Distinguishes stadium/arena naming rights from trophy, league division, award, practice facility, or digital property naming rights. [ENUM-REF-CANDIDATE: venue_naming_right|trophy_naming_right|division_naming_right|award_naming_right|practice_facility|digital_property — promote to reference product]. Valid values are `venue_naming_right|trophy_naming_right|division_naming_right|award_naming_right|practice_facility|digital_property`',
    `annual_fee_amount` DECIMAL(18,2) COMMENT 'Annual fee payable by the naming rights holder to the rights owner, as stipulated in the agreement. Used for annual revenue recognition and Workday Adaptive Planning financial forecasting.',
    `broadcast_mention_count_min` STRING COMMENT 'Minimum number of on-air brand mentions of the named assets sponsor name contractually required per broadcast event or season, as specified in the naming rights agreement.',
    `broadcast_mention_requirement` STRING COMMENT 'Contractual specification for how and how often the named assets sponsor brand must be verbally or graphically referenced during broadcast coverage, including OTT and RSN distribution. Managed in alignment with Dalet Galaxy broadcast workflow.',
    `contract_document_ref` STRING COMMENT 'Reference identifier or URL to the executed naming rights contract document stored in the enterprise document management system or SAP S/4HANA document management. Enables direct access to the legal instrument.',
    `cpm_rate` DECIMAL(18,2) COMMENT 'Agreed Cost Per Mille (CPM) rate used to value the media impressions delivered through the naming rights agreement. Supports ROI reporting and sponsor performance analytics.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the naming rights agreement record was first created in the data platform. Supports audit trail and data lineage requirements under SOX and GDPR.',
    `digital_url` STRING COMMENT 'The official digital property URL (website or primary digital destination) for the named asset reflecting the sponsors brand, as required by the naming rights agreement.',
    `digital_url_change_required` BOOLEAN COMMENT 'Indicates whether the naming rights agreement requires changes to digital property URLs (website domains, social media handles, app store listings) to reflect the sponsors brand name.',
    `dispute_resolution_body` STRING COMMENT 'Name of the arbitration or dispute resolution body specified in the naming rights agreement for resolving contractual disputes (e.g., CAS - Court of Arbitration for Sport, ICC International Court of Arbitration).',
    `effective_end_date` DATE COMMENT 'Calendar date on which the naming rights agreement expires and the sponsors brand name is no longer contractually applied to the named asset. Nullable for open-ended agreements.',
    `effective_start_date` DATE COMMENT 'Calendar date on which the naming rights agreement becomes legally binding and the named asset officially adopts the sponsors brand name. Aligns with the contract commencement date in SAP S/4HANA.',
    `exclusivity_category` STRING COMMENT 'Industry or product category in which the naming rights holder is granted exclusivity, preventing competing brands in the same category from obtaining naming rights on the same property (e.g., Financial Services, Automotive, Telecommunications).',
    `exclusivity_scope` STRING COMMENT 'Geographic scope of the exclusivity granted to the naming rights holder. Determines the territorial boundaries within which competing brands in the same category are excluded.. Valid values are `global|national|regional|local`',
    `fee_currency_code` STRING COMMENT 'ISO 4217 three-letter currency code in which the naming rights fees are denominated (e.g., USD, GBP, EUR). Required for multi-currency financial consolidation in SAP S/4HANA.. Valid values are `^[A-Z]{3}$`',
    `fee_escalation_rate` DECIMAL(18,2) COMMENT 'Annual percentage rate at which the naming rights fee escalates over the term of the agreement (e.g., 0.0300 = 3% per annum). Used in Workday Adaptive Planning for multi-year revenue projections.',
    `gdpr_compliant_flag` BOOLEAN COMMENT 'Indicates whether the data processing activities associated with this naming rights agreement (fan data used in activation campaigns) have been reviewed for GDPR compliance. Relevant for EU market activations.',
    `governing_law_country` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the jurisdiction whose laws govern the naming rights agreement. Relevant for dispute resolution and compliance with local regulations.. Valid values are `^[A-Z]{3}$`',
    `grp_commitment` DECIMAL(18,2) COMMENT 'Contractually committed Gross Rating Point (GRP) delivery for broadcast and media exposure associated with the naming rights agreement. Used to measure and report media value delivered to the sponsor.',
    `ip_rights_included_flag` BOOLEAN COMMENT 'Indicates whether the naming rights agreement grants the sponsor Intellectual Property (IP) usage rights, such as the right to use league logos, team marks, or event trademarks in their own marketing.',
    `named_asset_name` STRING COMMENT 'The official branded name of the asset as it appears publicly following the naming rights agreement (e.g., Acme Arena, TechCorp Stadium). This is the name used in all broadcast mentions, signage, and digital properties.',
    `named_asset_prior_name` STRING COMMENT 'The name of the asset prior to the current naming rights agreement. Used for historical reference, fan communications, and transition period signage management.',
    `named_asset_type` STRING COMMENT 'Category of the physical or intangible property subject to the naming rights. Determines applicable signage, broadcast, and digital obligations. [ENUM-REF-CANDIDATE: stadium|arena|practice_facility|trophy|award|league_division|digital_property|broadcast_segment — promote to reference product]',
    `nil_compliance_flag` BOOLEAN COMMENT 'Indicates whether the naming rights agreement has been reviewed and confirmed compliant with applicable Name Image and Likeness (NIL) regulations, particularly relevant when athlete names or likenesses are incorporated into the named asset branding.',
    `payment_schedule_type` STRING COMMENT 'Frequency or structure of fee payments from the naming rights holder to the rights owner as defined in the contract. Drives accounts receivable scheduling in SAP S/4HANA.. Valid values are `annual|semi_annual|quarterly|monthly|lump_sum`',
    `renewal_notice_days` STRING COMMENT 'Number of calendar days prior to the agreement expiry by which the sponsor must exercise their renewal option. Triggers automated renewal outreach workflows in Salesforce CRM.',
    `renewal_option_flag` BOOLEAN COMMENT 'Indicates whether the naming rights agreement includes a contractual option for the sponsor to renew at the end of the current term. True = renewal option exists; False = no renewal option.',
    `renewal_option_terms` STRING COMMENT 'Free-text description of the renewal option conditions, including notice period, fee adjustment methodology, and any right-of-first-refusal provisions as specified in the contract.',
    `roi_target_pct` DECIMAL(18,2) COMMENT 'Contractually agreed or internally benchmarked Return on Investment (ROI) target percentage for the naming rights agreement, used to evaluate sponsor value delivery and guide renewal negotiations.',
    `signage_count` STRING COMMENT 'Total number of physical and digital signage units contractually required to display the sponsors brand name under the naming rights agreement.',
    `signage_spec_description` STRING COMMENT 'Detailed description of the physical and digital signage obligations under the naming rights agreement, including placement locations, dimensions, illumination requirements, and brand standards compliance.',
    `sox_reportable_flag` BOOLEAN COMMENT 'Indicates whether this naming rights agreement meets the materiality threshold requiring disclosure under SOX financial controls for public company reporting. Drives inclusion in SEC financial reporting.',
    `term_years` STRING COMMENT 'Total contractual duration of the naming rights agreement expressed in whole years. Supports long-term revenue planning and renewal pipeline management.',
    `termination_clause_flag` BOOLEAN COMMENT 'Indicates whether the agreement contains an early termination clause allowing either party to exit the agreement before the effective end date under defined conditions.',
    `termination_fee_amount` DECIMAL(18,2) COMMENT 'Contractual penalty or fee payable upon early termination of the naming rights agreement. Expressed in the contract currency. Applicable only when termination_clause_flag is True.',
    `total_fee_amount` DECIMAL(18,2) COMMENT 'Total contractual value of the naming rights agreement over the full term, expressed in the contract currency. Used for financial reporting under SAP S/4HANA FI/CO and SOX compliance disclosures.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when the naming rights agreement record was most recently modified in the data platform. Supports change tracking, audit compliance, and Silver layer data freshness monitoring.',
    CONSTRAINT pk_naming_right PRIMARY KEY(`naming_right_id`)
) COMMENT 'Master record for venue and property naming rights agreements. Captures named asset (stadium, arena, practice facility, trophy, award, league division), naming rights holder (sponsor), naming rights fee, term start and end dates, signage specifications, broadcast mention requirements, digital property URL changes, and renewal option details. Distinct from general deal terms due to the long-term, high-value, and multi-property nature of naming rights.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`sponsorship`.`ad_inventory` (
    `ad_inventory_id` BIGINT COMMENT 'Unique surrogate identifier for each sponsorship and advertising inventory asset record in the master catalog. Primary key for the sponsorship_ad_inventory product.',
    `athlete_profile_id` BIGINT COMMENT 'Foreign key linking to athlete.athlete_profile. Business justification: Athlete-specific inventory units (jersey patch slots, athlete appearance placements, athlete social media inventory) must reference the athlete whose likeness constitutes the asset. Inventory valuatio',
    `channel_id` BIGINT COMMENT 'Foreign key linking to broadcast.channel. Business justification: Broadcast-integrated ad inventory (is_broadcast_integrated flag) is valued and managed per broadcast channel. Channel subscriber_count, platform_type, and territory directly drive CPM benchmarking and',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Ad inventory assets are often franchise-specific (in-stadium digital boards, jersey patches, tunnel branding for Team X). Inventory management systems must identify which franchises assets are being ',
    `governing_body_id` BIGINT COMMENT 'Foreign key linking to compliance.governing_body. Business justification: Ad inventory (broadcast slots, in-venue signage) is subject to governing body rules on placement, content restrictions, and exclusivity categories. The sponsorship_ad_inventory has ada_compliant and g',
    `inventory_unit_id` BIGINT COMMENT 'Foreign key linking to sponsorship.inventory_unit. Business justification: sponsorship_ad_inventory is the catalog of available sponsorship and advertising inventory assets. inventory_unit is the master reference table defining the unit types, formats, pricing benchmarks, an',
    `jurisdiction_id` BIGINT COMMENT 'Foreign key linking to gaming.gaming_jurisdiction. Business justification: Betting-related ad inventory (odds widgets, sponsored betting segments) is only available in jurisdictions where the operator is licensed. Inventory managers must validate jurisdiction compliance befo',
    `league_id` BIGINT COMMENT 'Identifier of the league or competition to which this inventory asset is associated. Governs exclusivity restrictions, CBA (Collective Bargaining Agreement) compliance, and league-level sponsorship category protections.',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Ad inventory availability is defined per league season. The plain-text season_year column is a denormalization signal. Structured FK to league.season enables season-level inventory planning, availab',
    `operator_id` BIGINT COMMENT 'Foreign key linking to gaming.operator. Business justification: Ad inventory units reserved exclusively for or restricted to specific gaming operators (category exclusivity) require direct operator reference. Inventory management teams track which licensed operato',
    `platform_channel_id` BIGINT COMMENT 'Foreign key linking to content.platform_channel. Business justification: Ad inventory units belong to specific platform channels (OTT, broadcast, digital). Inventory managers need this FK for availability management, DRM enforcement per channel, and CPM pricing. asset_chan',
    `policy_id` BIGINT COMMENT 'Foreign key linking to compliance.policy. Business justification: Ad inventory units are subject to compliance policies (FCC advertising rules for broadcast inventory, GDPR for targeted digital inventory, WADA restrictions on prohibited sponsor categories). sponsors',
    `property_id` BIGINT COMMENT 'Identifier of the Sports Entertainment property (venue, broadcast channel, OTT platform, mobile app, or league) to which this inventory asset belongs. Links the asset to its owning property for rights management and revenue attribution.',
    `venue_id` BIGINT COMMENT 'Identifier of the specific venue where this inventory asset is physically located. Applicable for in-venue asset types such as LED perimeter boards, stadium signage, naming rights units, and VIP hospitality suites. Null for purely digital or broadcast assets.',
    `ada_compliant` BOOLEAN COMMENT 'Indicates whether this inventory asset (particularly in-venue assets such as signage, hospitality suites, and PA systems) meets ADA (Americans with Disabilities Act) accessibility requirements. Mandatory for venue-based assets in US markets. Supports compliance reporting.',
    `approval_status` STRING COMMENT 'The internal governance approval status of this inventory asset before it may be listed for sale. approved indicates the asset has passed commercial, legal, and compliance review; pending_review indicates it is under review; rejected indicates it failed review; draft indicates it is being prepared for submission.. Valid values are `approved|pending_review|rejected|draft`',
    `assessed_value_per_unit` DECIMAL(18,2) COMMENT 'The independently assessed fair market value of a single unit of this inventory asset, expressed in the valuation currency. Represents the SSOT for what each asset unit is worth in the current market. Used as the floor price in sponsor negotiations and for ROI (Return on Investment) reporting.',
    `asset_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying the inventory asset across all Sports Entertainment properties and Salesforce CRM. Used in sponsor proposals, contracts, and activation briefs as the canonical asset reference.. Valid values are `^[A-Z]{2,6}-[A-Z0-9]{3,10}-[0-9]{4,8}$`',
    `asset_name` STRING COMMENT 'Human-readable name of the inventory asset (e.g., Main Pitch LED Perimeter Board East Side, OTT Pre-Roll 30s Slot — League Pass App, Naming Rights Unit — North Stand). Used in sales decks, activation plans, and reporting.',
    `asset_type` STRING COMMENT 'Category of the inventory asset defining its physical or digital format. Examples include LED perimeter board, broadcast billboard, digital overlay, PA announcement slot, in-app banner, OTT pre-roll, social media post, VIP hospitality suite, naming rights unit, jersey sponsorship patch, stadium signage. [ENUM-REF-CANDIDATE: led_perimeter_board|broadcast_billboard|digital_overlay|pa_announcement|in_app_banner|ott_pre_roll|social_media_post|vip_hospitality_suite|naming_rights|jersey_patch|stadium_signage|scoreboard_display|field_logo|digital_out_of_home|podcast_sponsorship — promote to reference product]',
    `audience_demographic_profile` STRING COMMENT 'Description of the primary audience demographic profile associated with this inventory asset (e.g., Male 18-34, ABC1, sports enthusiast, Family audience, mixed gender, 25-54). Sourced from Adobe Experience Platform fan analytics or Nielsen audience measurement. Used in sponsor targeting and CPM justification.',
    `availability_status` STRING COMMENT 'Current availability state of the inventory asset in the sponsorship sales lifecycle. available indicates the asset is open for sale; sold indicates it is committed to a sponsor; reserved indicates a hold pending contract execution; held indicates a short-term sales hold; retired indicates the asset is no longer offered; pending_approval indicates the asset is awaiting internal sign-off before listing.. Valid values are `available|sold|reserved|held|retired|pending_approval`',
    `cpm_benchmark` DECIMAL(18,2) COMMENT 'The industry benchmark CPM (Cost Per Mille) rate for this asset type and channel, expressed in the assets valuation currency. Represents the market cost per 1,000 impressions used to benchmark assessed value against industry norms. Sourced from Nielsen, independent agency, or Sports Entertainment commercial intelligence.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this inventory asset record was first created in the sponsorship ad inventory catalog. Provides the audit trail creation anchor for SOX compliance and data lineage tracking.',
    `effective_from_date` DATE COMMENT 'The date from which this inventory asset record is valid and available for sale. Supports temporal versioning of the inventory catalog, ensuring that historical valuations and availability states are preserved for audit and benchmarking purposes.',
    `effective_to_date` DATE COMMENT 'The date after which this inventory asset record is no longer valid or available for sale. Null indicates the record is currently active. Used for temporal versioning and historical audit of the inventory catalog.',
    `estimated_impressions` BIGINT COMMENT 'Estimated number of audience impressions delivered per unit activation of this inventory asset, based on Nielsen media measurement, broadcast ratings, or venue attendance data. Used as the primary input for CPM (Cost Per Mille) valuation and GRP (Gross Rating Point) calculations in sponsor proposals.',
    `event_type_eligibility` STRING COMMENT 'Defines the types of events for which this inventory asset is eligible to be activated (e.g., regular_season, playoffs, finals, international, concert, all). Restricts asset availability to appropriate event contexts and supports event-specific packaging.',
    `exclusivity_category` STRING COMMENT 'The commercial exclusivity classification of the inventory asset, defining whether a sponsor receives category exclusivity (e.g., exclusive automotive partner), sub-category exclusivity, or non-exclusive placement. Governs competitive separation rules and sponsor conflict checks. [ENUM-REF-CANDIDATE: category_exclusive|sub_category_exclusive|non_exclusive|presenting_sponsor|title_sponsor|co_sponsor — promote to reference product]',
    `gdpr_data_usage_flag` BOOLEAN COMMENT 'Indicates whether activation of this inventory asset involves the collection or processing of fan personal data (True), triggering GDPR (General Data Protection Regulation) or CCPA compliance obligations. Applicable to digital assets such as in-app banners, OTT pre-rolls, and personalized digital overlays that use fan behavioral data for targeting.',
    `grp_rating` DECIMAL(18,2) COMMENT 'The GRP (Gross Rating Point) value assigned to this inventory asset, representing the percentage of the target audience reached multiplied by the average frequency of exposure. Used for broadcast and media inventory valuation and sponsor ROI (Return on Investment) reporting. Sourced from Nielsen or independent agency assessment.',
    `internal_owner_team` STRING COMMENT 'The internal Sports Entertainment business unit or team responsible for managing and selling this inventory asset (e.g., Global Partnerships, Broadcast Sales, Venue Commercial, Digital Partnerships). Used for revenue attribution, KPI (Key Performance Indicator) reporting, and workflow routing.',
    `is_broadcast_integrated` BOOLEAN COMMENT 'Indicates whether this inventory asset is integrated into a broadcast or OB (Outside Broadcast) production feed (True), meaning it appears in the televised or streamed broadcast of an event. Broadcast-integrated assets carry higher CPM values and are subject to FCC broadcast regulation and RSN (Regional Sports Network) rights restrictions.',
    `is_digital` BOOLEAN COMMENT 'Indicates whether this inventory asset is a digital placement (True) or a physical/static placement (False). Digital assets include OTT pre-rolls, in-app banners, digital overlays, and social media posts. Physical assets include static signage, LED boards, and naming rights plaques. Drives DRM (Digital Rights Management) and DAM (Digital Asset Management) workflow routing.',
    `is_naming_rights` BOOLEAN COMMENT 'Indicates whether this inventory asset represents a naming rights unit (True), such as a venue naming rights package or a competition naming rights package. Naming rights assets have distinct legal, IP (Intellectual Property), and valuation characteristics and require separate governance approval.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this inventory asset record was most recently modified, including changes to availability status, valuation, capacity, or approval status. Supports change data capture in the Databricks Silver Layer and audit trail requirements.',
    `list_price_per_unit` DECIMAL(18,2) COMMENT 'The standard published list price for a single unit of this inventory asset, expressed in the valuation currency. Represents the starting price point in sponsor negotiations before any package discounts or deal-specific adjustments. Distinct from assessed_value_per_unit which reflects independent market valuation.',
    `max_units_per_sponsor` STRING COMMENT 'The maximum number of units of this inventory asset that a single sponsor may purchase, enforcing competitive separation and preventing monopolization of high-visibility placements. Null indicates no per-sponsor cap.',
    `min_commitment_units` STRING COMMENT 'The minimum number of units a sponsor must purchase to activate this inventory asset. Enforces commercial packaging rules and prevents sub-economic placements. For example, a broadcast billboard may require a minimum of 10 spots per broadcast.',
    `placement_location_description` STRING COMMENT 'Detailed description of the physical or digital placement location of the inventory asset (e.g., East perimeter board, pitch-side, between 18-yard box and halfway line, Pre-roll slot on League Pass OTT app home screen, North Stand fascia, upper tier). Provides the specificity required for activation briefs and sponsor approval.',
    `production_spec_notes` STRING COMMENT 'Technical production specifications and creative requirements for this inventory asset, such as artwork dimensions, file format requirements, broadcast safe zones, LED pixel pitch, audio specifications for PA announcements, or digital ad unit specifications (IAB standards). Used by the activation and production teams.',
    `sponsor_category` STRING COMMENT 'The industry or product category of the sponsor occupying or targeted for this inventory asset (e.g., automotive, financial services, beverage, technology, insurance, apparel). Used for competitive exclusivity enforcement and category-based inventory packaging. [ENUM-REF-CANDIDATE: automotive|financial_services|beverage|technology|insurance|apparel|healthcare|telecommunications|retail|energy — promote to reference product]',
    `unit_count` STRING COMMENT 'Total number of discrete units available for this inventory asset type at the associated property. For example, the number of LED perimeter board panels, the number of OTT pre-roll slots per broadcast, or the number of PA announcement slots per event. Drives capacity planning and sell-through rate analysis.',
    `unit_duration_seconds` STRING COMMENT 'Duration in seconds of a single inventory unit for time-based assets such as broadcast billboards, OTT pre-roll slots, PA announcements, and digital overlays. Null for non-time-based assets such as naming rights or jersey patches. Standard broadcast durations include 15, 30, and 60 seconds.',
    `valuation_currency` STRING COMMENT 'ISO 4217 three-letter currency code in which the assessed value per unit and CPM benchmark are denominated (e.g., USD, GBP, EUR). Supports multi-currency operations across global Sports Entertainment markets.. Valid values are `^[A-Z]{3}$`',
    `valuation_date` DATE COMMENT 'The date on which the current assessed value per unit was determined. Used to track valuation currency and trigger re-valuation workflows when the valuation exceeds the maximum age threshold defined by Sports Entertainment commercial policy.',
    `valuation_methodology` STRING COMMENT 'The methodology used to derive the assessed value per unit for this inventory asset. broadcast_equivalency values the asset based on equivalent broadcast airtime cost; nielsen_media_value uses Nielsen-measured audience data; independent_agency reflects a third-party agency appraisal; internal_assessment reflects Sports Entertainment commercial team valuation; comparable_market uses comparable asset transactions.. Valid values are `broadcast_equivalency|nielsen_media_value|independent_agency|internal_assessment|comparable_market`',
    `valuation_source` STRING COMMENT 'The name of the organization or system that provided the assessed value (e.g., Nielsen Sports, Repucom, Two Circles, Sports Entertainment Internal Commercial Team, Octagon). Provides audit traceability for valuation figures used in sponsor proposals and financial reporting.',
    CONSTRAINT pk_ad_inventory PRIMARY KEY(`ad_inventory_id`)
) COMMENT 'Master catalog of available sponsorship and advertising inventory assets across all Sports Entertainment properties, including independently assessed market valuations. Captures asset type (LED perimeter board, broadcast billboard, digital overlay, PA announcement slot, in-app banner, OTT pre-roll, social media post, VIP hospitality suite, naming rights unit), property association (venue, broadcast channel, OTT platform, mobile app), capacity metrics (number of units, duration in seconds, estimated impressions), exclusivity category, current availability status. Includes valuation data: assessed value per unit, valuation methodology (broadcast equivalency, Nielsen media value, independent agency assessment), valuation date, valuation source, and currency. SSOT for what can be sold to sponsors, current market value of each asset, and benchmarking against industry CPM and GRP rates.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`sponsorship`.`inventory_allocation` (
    `inventory_allocation_id` BIGINT COMMENT 'Unique surrogate identifier for each inventory allocation record linking a specific ad inventory unit to a sponsorship deal or activation. Primary key for this transactional entity.',
    `activation_id` BIGINT COMMENT 'Reference to the specific brand activation or campaign deliverable this inventory allocation fulfills within the sponsorship deal.',
    `ad_inventory_id` BIGINT COMMENT 'Reference to the specific advertising or sponsorship inventory unit being allocated (e.g., LED board slot, broadcast spot, digital banner, naming rights panel, jersey patch position).',
    `broadcast_schedule_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_schedule. Business justification: Broadcast-integrated inventory allocations (delivery_start_date, delivery_end_date, channel) must be tied to specific broadcast schedule slots to confirm availability, prevent double-booking, and gene',
    `broadcast_window_id` BIGINT COMMENT 'Reference to the broadcast or media window (e.g., pre-game, halftime, post-game, OTT stream slot) during which this inventory allocation is scheduled for delivery.',
    `asset_id` BIGINT COMMENT 'Foreign key linking to content.asset. Business justification: Inventory allocations assign specific creative assets to inventory slots. Trafficking and fulfillment teams need this FK to verify DRM compliance and brand safety of the allocated creative before deli',
    `deal_id` BIGINT COMMENT 'Reference to the parent sponsorship deal or contract under which this inventory allocation is made. Links the allocation to its governing commercial agreement.',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Inventory allocations for franchise-specific assets (jersey patch, home game signage) must reference the franchise. Franchise-level allocation reporting and exclusivity enforcement require this direct',
    `inventory_unit_id` BIGINT COMMENT 'Reference to the specific advertising or sponsorship inventory unit being allocated (e.g., LED board slot, broadcast spot, digital banner, naming rights panel, jersey patch position).',
    `league_id` BIGINT COMMENT 'Reference to the league or competition governing body under whose jurisdiction this inventory allocation falls (e.g., NFL, NBA, FIFA). Relevant for league-mandated inventory restrictions and governing body approval requirements.',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Inventory allocations are made for specific league seasons. Season-level allocation reporting, sell-through rate analysis, and unsold inventory management are core commercial operations processes requ',
    `operator_id` BIGINT COMMENT 'Foreign key linking to gaming.operator. Business justification: Inventory allocations to gaming operator sponsors require operator reference for pre-delivery regulatory compliance checks — verifying the operators license is active in the delivery jurisdiction bef',
    `original_allocation_inventory_allocation_id` BIGINT COMMENT 'Reference to the original inventory allocation record that this make-good allocation is compensating for. Populated only when make_good_flag is True. Enables traceability of make-good chains.',
    `fixture_id` BIGINT COMMENT 'Reference to the specific sporting or entertainment event during which this inventory allocation is to be delivered (e.g., match, game, concert, tournament round).',
    `sponsor_id` BIGINT COMMENT 'Reference to the sponsor or brand partner to whom this inventory is allocated. Serves as the primary party reference for this transaction.',
    `venue_id` BIGINT COMMENT 'Reference to the venue or facility where this physical or digital inventory allocation is to be activated (e.g., stadium LED board, arena naming rights signage).',
    `actual_impressions_delivered` BIGINT COMMENT 'The actual number of audience impressions or exposures recorded upon delivery of this inventory allocation. Compared against impression_target to assess performance and trigger make-good provisions.',
    `actual_quantity_delivered` STRING COMMENT 'The actual number of inventory units delivered upon fulfillment of this allocation. Compared against allocated_quantity to determine fulfillment rate and identify make-good obligations.',
    `allocated_quantity` STRING COMMENT 'Number of inventory units allocated in this record (e.g., number of broadcast spots, number of digital impressions blocks, number of signage panels). Represents the principal quantitative fact of this allocation transaction.',
    `allocated_value` DECIMAL(18,2) COMMENT 'The commercial value assigned to this specific inventory allocation, representing the portion of the sponsorship deals total contract value attributable to this unit. Used for revenue recognition, ROI tracking, and deal fulfillment reporting.',
    `allocation_date` DATE COMMENT 'The calendar date on which this inventory unit was formally allocated to the sponsorship deal or activation. Represents the principal business event date for this transaction.',
    `allocation_reference_number` STRING COMMENT 'Externally-known business identifier for this allocation transaction, used in sponsor-facing communications, fulfillment reports, and cross-system reconciliation (e.g., CRM opportunity line reference, SAP SD delivery order number).',
    `allocation_status` STRING COMMENT 'Current lifecycle state of this inventory allocation. reserved indicates a hold pending confirmation; confirmed indicates a committed booking; delivered indicates fulfillment is complete; cancelled indicates the allocation was voided; pending_approval indicates awaiting internal or sponsor sign-off.. Valid values are `reserved|confirmed|delivered|cancelled|pending_approval`',
    `allocation_timestamp` TIMESTAMP COMMENT 'Precise date and time when this inventory allocation record was created in the system, capturing the exact moment of reservation or booking action.',
    `approval_date` DATE COMMENT 'The date on which this inventory allocation received formal approval from the required approving authority. Supports audit trail and compliance reporting.',
    `approval_required_flag` BOOLEAN COMMENT 'Indicates whether this inventory allocation requires explicit approval from a league governing body, broadcast rights holder, or internal compliance team before it can be confirmed and delivered.',
    `approved_by` STRING COMMENT 'Name or identifier of the individual or governing body that approved this inventory allocation. Populated when approval_required_flag is True and the allocation has been approved.',
    `cancellation_reason` STRING COMMENT 'Reason code explaining why this inventory allocation was cancelled. Used for operational analysis, sponsor relationship management, and capacity planning adjustments.. Valid values are `sponsor_request|event_cancelled|inventory_conflict|deal_terminated|force_majeure|operational_error`',
    `cancelled_timestamp` TIMESTAMP COMMENT 'Date and time when this inventory allocation was cancelled. Populated only when allocation_status is cancelled. Supports audit trail and capacity reclamation workflows.',
    `channel` STRING COMMENT 'The media or activation channel through which this inventory allocation is delivered (e.g., broadcast TV, OTT streaming, in-venue, digital web, social media). Drives measurement methodology and reporting standards. [ENUM-REF-CANDIDATE: broadcast_tv|ott_streaming|in_venue|digital_web|social_media|mobile_app|radio|print — promote to reference product]',
    `confirmed_timestamp` TIMESTAMP COMMENT 'Date and time when this inventory allocation was formally confirmed by both the sponsorship operations team and the sponsor, transitioning from reserved to confirmed status.',
    `cpm_rate` DECIMAL(18,2) COMMENT 'The Cost Per Mille (CPM) rate applied to this inventory allocation, representing the cost per one thousand impressions or audience exposures. Standard pricing metric for digital and broadcast advertising inventory in the sports-entertainment industry.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the allocated_value amount (e.g., USD, EUR, GBP). Supports multi-currency sponsorship deals across global markets.. Valid values are `^[A-Z]{3}$`',
    `delivered_timestamp` TIMESTAMP COMMENT 'Date and time when fulfillment of this inventory allocation was completed and verified, transitioning the record to delivered status. Used for ROI reporting and sponsor proof-of-performance.',
    `delivery_end_date` DATE COMMENT 'The date by which this inventory allocation must be fully delivered or activated. Defines the closing boundary of the fulfillment window and drives SLA compliance tracking.',
    `delivery_start_date` DATE COMMENT 'The date from which this inventory allocation is scheduled to begin delivery or activation. Defines the opening boundary of the fulfillment window.',
    `exclusivity_category` STRING COMMENT 'The product or service category for which exclusivity is granted (e.g., Automotive, Financial Services, Beverage - Alcohol, Telecommunications). Populated only when exclusivity_flag is True. Used to enforce category conflict checks during deal negotiations.',
    `exclusivity_flag` BOOLEAN COMMENT 'Indicates whether this inventory allocation carries category exclusivity for the sponsor, preventing competing brands in the same product or service category from receiving the same inventory type during the same event or broadcast window.',
    `geographic_market` STRING COMMENT 'ISO 3166-1 alpha-3 country code representing the primary geographic market for this inventory allocation. Supports multi-market sponsorship deals and regional rights management.. Valid values are `^[A-Z]{3}$`',
    `grp_target` DECIMAL(18,2) COMMENT 'The target Gross Rating Point (GRP) value committed for this inventory allocation, representing the expected audience reach multiplied by frequency. Used for broadcast and media inventory performance measurement and sponsor ROI reporting.',
    `impression_target` BIGINT COMMENT 'The target number of audience impressions or exposures committed for this inventory allocation. Used for digital and broadcast inventory performance tracking and sponsor proof-of-performance reporting.',
    `inventory_type` STRING COMMENT 'Classification of the advertising or sponsorship inventory unit being allocated. Drives fulfillment workflows, measurement methodology (CPM, GRP, impressions), and reporting. [ENUM-REF-CANDIDATE: broadcast_spot|digital_display|venue_signage|jersey_patch|naming_rights|social_media|print|activation_space — promote to reference product]',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Date and time when this inventory allocation record was last updated. Supports change tracking, audit trail, and incremental data pipeline processing in the Databricks Silver Layer.',
    `make_good_flag` BOOLEAN COMMENT 'Indicates whether this inventory allocation was created as a make-good (compensatory replacement) for a previously under-delivered or cancelled allocation. Make-goods are contractual obligations to sponsors when original delivery commitments are not met.',
    `notes` STRING COMMENT 'Free-text field for operational notes, special instructions, or contextual information related to this inventory allocation (e.g., creative specifications, sponsor preferences, technical delivery requirements).',
    `placement_position` STRING COMMENT 'Specific placement position or location descriptor for this inventory allocation (e.g., North End LED Row 1, Halftime Break Slot 2, Homepage Banner Top, Left Sleeve Jersey Patch). Provides granular fulfillment and proof-of-performance detail.',
    `priority_tier` STRING COMMENT 'Commercial priority tier assigned to this allocation, reflecting the sponsors deal level and governing conflict resolution when inventory is oversubscribed. Higher tiers receive preferential placement and first-right-of-refusal on premium inventory.. Valid values are `platinum|gold|silver|bronze|standard`',
    `rate_card_value` DECIMAL(18,2) COMMENT 'The published or standard rate card value for this inventory unit prior to any negotiated discount or deal adjustment. Enables calculation of discount depth and benchmarking of deal terms against market rates.',
    `unit_of_measure` STRING COMMENT 'The unit in which the allocated quantity is expressed (e.g., spots for broadcast, impressions for digital, panels for venue signage, seconds for broadcast duration, placements for jersey or naming rights).. Valid values are `spots|impressions|panels|seconds|placements|activations`',
    CONSTRAINT pk_inventory_allocation PRIMARY KEY(`inventory_allocation_id`)
) COMMENT 'Transactional record linking specific ad inventory units to sponsorship deals and activations. Captures allocation date, allocated quantity, event or broadcast window, exclusivity flag, priority tier, and allocation status (reserved, confirmed, delivered, cancelled). Prevents double-booking of inventory assets and supports capacity planning for future deal negotiations.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`sponsorship`.`performance_metric` (
    `performance_metric_id` BIGINT COMMENT 'Unique surrogate identifier for each sponsorship performance metric record in the Silver Layer lakehouse. Primary key for this transactional measurement entity.',
    `activation_id` BIGINT COMMENT 'Reference to the specific brand activation or deliverable associated with this performance measurement (e.g., jersey logo placement, broadcast integration, in-venue signage).',
    `athlete_profile_id` BIGINT COMMENT 'Foreign key linking to athlete.athlete_profile. Business justification: Sponsorship ROI reporting requires attributing brand recall, social engagement, and impression metrics to a specific athlete. Existing FK covers athlete_contract; athlete_profile is the master identit',
    `audience_rating_id` BIGINT COMMENT 'Foreign key linking to broadcast.audience_rating. Business justification: Performance metrics track grp_delivered and broadcast_airtime_seconds sourced from audience measurement. Linking to audience_rating provides traceability from contracted KPI to the measurement record ',
    `audit_engagement_id` BIGINT COMMENT 'Foreign key linking to compliance.audit_engagement. Business justification: Sponsorship performance metrics (GRP delivery, impression fulfillment) are subject to compliance audit engagements to verify accuracy of reported figures for sponsor ROI reporting. Auditors need to tr',
    `betting_market_id` BIGINT COMMENT 'Foreign key linking to gaming.betting_market. Business justification: ROI reports for betting operator sponsors measure engagement at the market level (e.g., handle volume on sponsored markets, CTR on odds overlays). Performance metrics must reference the specific betti',
    `channel_id` BIGINT COMMENT 'Foreign key linking to broadcast.channel. Business justification: Sponsorship performance metrics track broadcast_airtime_seconds and impressions by channel. Linking to broadcast.channel enables channel-level ROI reporting, CPM analysis by platform and territory, an',
    `contest_id` BIGINT COMMENT 'Foreign key linking to gaming.contest. Business justification: Sponsorship KPIs are measured against specific gaming contests (e.g., branded DFS contest series). Sponsorship analysts reporting on contest-tied activation performance — impressions, engagement, priz',
    `asset_id` BIGINT COMMENT 'Foreign key linking to content.asset. Business justification: Sponsorship ROI reporting requires linking performance metrics (impressions, brand recall, CPM realized) to the specific creative asset that ran. Analytics teams measure asset-level effectiveness for ',
    `deal_id` BIGINT COMMENT 'Foreign key linking to sponsorship.deal. Business justification: performance_metric captures measured sponsorship performance data against contracted KPIs. While performance_metric already links to activation (which in turn links to deal), many performance metrics ',
    `segment_id` BIGINT COMMENT 'Foreign key linking to fan.segment. Business justification: Sponsorship KPIs (NPS lift, brand recall, reach) are measured against specific fan segments as contracted audience targets. Linking performance_metric to fan.segment enables segment-level sponsor ROI ',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Sponsorship KPIs — jersey patch impressions, in-arena GRP, brand recall scores — are measured at franchise level. Franchise-level performance reporting is a standard sponsor deliverable; without this ',
    `league_id` BIGINT COMMENT 'Reference to the sports league or competition governing body context in which this sponsorship performance metric was measured (e.g., NFL, NBA, MLS, FIFA). Enables league-level aggregation and compliance with league sponsorship governance rules.',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Sponsorship KPIs (GRP, impressions, brand recall) are measured and reported per league season. Season-level KPI reporting drives renewal decisions and ROI analysis; no structured season FK currently e',
    `live_feed_id` BIGINT COMMENT 'Foreign key linking to broadcast.live_feed. Business justification: Sponsorship performance metrics (broadcast_airtime_seconds, grp_delivered, impressions) are measured against specific live feed broadcasts. The live_feed record provides actual start/end times, feed_s',
    `nil_agreement_id` BIGINT COMMENT 'Foreign key linking to athlete.nil_agreement. Business justification: NIL deal ROI measurement requires linking performance metrics directly to the NIL agreement being evaluated. Athlete management, agents, and sponsors use this for NIL deal renewal decisions, performan',
    `fixture_id` BIGINT COMMENT 'Reference to the specific sports or entertainment event during which this performance metric was captured, if applicable (e.g., a specific match, concert, or broadcast window).',
    `revenue_recognition_schedule_id` BIGINT COMMENT 'Foreign key linking to finance.revenue_recognition_schedule. Business justification: Performance metrics drive variable consideration adjustments under IFRS 15/ASC 606. When KPIs (impressions, GRP, NPS lift) are met or missed, the revenue recognition schedule must be updated. Direct F',
    `sponsor_id` BIGINT COMMENT 'Reference to the sponsor (brand/company) whose contracted KPI performance is being measured in this record.',
    `venue_id` BIGINT COMMENT 'Reference to the venue where in-venue sponsorship activations were measured. Relevant for naming rights, in-venue signage, and experiential activation metrics.',
    `activation_channel` STRING COMMENT 'The specific channel or placement through which the sponsorship was activated and measured. Covers broadcast TV, OTT (Over-The-Top) streaming, in-venue signage, jersey sponsorship, naming rights, digital display, social media, PPV (Pay-Per-View), and other channels. [ENUM-REF-CANDIDATE: broadcast_tv|ott_streaming|in_venue_signage|jersey_sponsorship|naming_rights|digital_display|social_media|print|radio|ppv — promote to reference product]',
    `actual_value` DECIMAL(18,2) COMMENT 'The measured actual value delivered for this sponsorship KPI during the measurement period. Sourced from third-party measurement providers (Nielsen, Kantar) or internal analytics systems.',
    `brand_recall_score` DECIMAL(18,2) COMMENT 'Unaided or aided brand recall score measured via consumer survey panels (Kantar, Nielsen) during the measurement period. Expressed as a percentage of surveyed audience who recalled the sponsor brand in the context of the sports/entertainment property.',
    `broadcast_airtime_seconds` STRING COMMENT 'Total number of seconds of broadcast airtime during which the sponsors brand was visible or mentioned during the measurement period. Tracked via Dalet Galaxy broadcast workflow and third-party monitoring services.',
    `contracted_target_value` DECIMAL(18,2) COMMENT 'The agreed-upon target value for this KPI as stipulated in the sponsorship contract. Serves as the benchmark against which actual performance is measured for fulfillment and ROI reporting.',
    `cpm_realized` DECIMAL(18,2) COMMENT 'Actual Cost Per Mille (cost per 1,000 impressions) realized for this sponsorship activation during the measurement period. Used to benchmark media efficiency against contracted CPM rates and industry benchmarks.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this performance metric record was first created in the system. Audit trail field for data lineage and compliance with SOX financial controls and GDPR data processing records.',
    `data_source` STRING COMMENT 'The originating data source or measurement provider that supplied the actual metric value. Used for data lineage, audit, and credibility assessment in sponsor-facing ROI reports. [ENUM-REF-CANDIDATE: nielsen|kantar|internal_analytics|adobe_experience_platform|social_platform_api|venue_analytics|manual — 7 candidates stripped; promote to reference product]',
    `data_source_report_reference` STRING COMMENT 'The external report or file identifier from the measurement data source (e.g., Nielsen report ID, Kantar study reference number) that this metric record was derived from. Enables traceability back to the source measurement report.',
    `frequency` DECIMAL(18,2) COMMENT 'Average number of times the target audience was exposed to the sponsorship asset (logo, brand mention, advertisement) during the measurement period. Component of GRP calculation.',
    `fulfillment_status` STRING COMMENT 'Assessment of whether the contracted KPI target was met for this measurement period. Fulfilled = actual >= target; Partially Fulfilled = actual between 80-99% of target; Unfulfilled = actual < 80% of target; Over-Delivered = actual > 110% of target.. Valid values are `fulfilled|partially_fulfilled|unfulfilled|over_delivered|not_applicable`',
    `grp_delivered` DECIMAL(18,2) COMMENT 'Total Gross Rating Points delivered for broadcast and media sponsorship activations during the measurement period. GRP = Reach% × Frequency. Core broadcast sponsorship KPI used in media valuation and ROI reporting.',
    `impressions` BIGINT COMMENT 'Total number of times the sponsors brand asset (logo, advertisement, naming rights mention) was served or displayed across all channels (broadcast, digital, in-venue) during the measurement period.',
    `in_venue_dwell_time_seconds` STRING COMMENT 'Average number of seconds fans spent in proximity to or engaged with in-venue sponsor activations (branded zones, experiential areas, digital signage) during the measurement period. Captured via venue analytics systems.',
    `is_contracted_kpi` BOOLEAN COMMENT 'Indicates whether this metric corresponds to a formally contracted KPI obligation in the sponsorship agreement (True) or is a supplementary/bonus metric tracked for additional insight (False). Drives fulfillment compliance reporting.',
    `make_good_required` BOOLEAN COMMENT 'Indicates whether a make-good (compensatory delivery of additional sponsorship inventory) is required due to under-delivery against the contracted KPI target. Triggers make-good workflow in sponsorship fulfillment operations.',
    `measurement_methodology` STRING COMMENT 'The methodology used to capture and validate this performance metric. Determines the reliability and comparability of the measurement. Examples: panel survey (Nielsen/Kantar), set-top box data, digital pixel tracking, AI image recognition for logo exposure, manual audit. [ENUM-REF-CANDIDATE: panel_survey|set_top_box|digital_pixel|manual_audit|ai_image_recognition|third_party_monitor|internal_analytics — 7 candidates stripped; promote to reference product]',
    `measurement_period_end` DATE COMMENT 'End date of the measurement window during which the sponsorship KPI data was collected. Together with measurement_period_start defines the reporting interval.',
    `measurement_period_start` DATE COMMENT 'Start date of the measurement window during which the sponsorship KPI data was collected. Aligns with contracted reporting periods (weekly, monthly, quarterly, seasonal).',
    `measurement_status` STRING COMMENT 'Current lifecycle state of this performance metric record. Tracks the workflow from initial capture through sponsor verification and final acceptance used in renewal negotiations.. Valid values are `draft|pending_verification|verified|disputed|finalized|voided`',
    `measurement_timestamp` TIMESTAMP COMMENT 'The precise date and time when this performance metric observation was recorded or ingested from the measurement data source (Nielsen, Kantar, internal analytics platform). Represents the principal real-world event time.',
    `metric_category` STRING COMMENT 'High-level category grouping the metric type for reporting and ROI analysis. Enables aggregation across activation channels (broadcast, digital, in-venue, brand health, social media, print).. Valid values are `broadcast|digital|in_venue|brand_health|social_media|print`',
    `metric_reference_code` STRING COMMENT 'Externally-known business identifier for this performance metric record, used in ROI reports, renewal negotiations, and sponsor-facing dashboards. Format: PM-YYYYMMDD-XXXX.. Valid values are `^PM-[0-9]{8}-[A-Z0-9]{4}$`',
    `metric_type` STRING COMMENT 'Classification of the sponsorship KPI being measured. Covers broadcast, digital, in-venue, and brand health metrics. [ENUM-REF-CANDIDATE: grp_delivered|cpm_realized|impressions|reach|frequency|brand_recall_score|nps_lift|social_engagement_rate|broadcast_airtime_seconds|in_venue_dwell_time|jersey_logo_exposure|naming_rights_mention|digital_banner_clicks|share_of_voice — promote to reference product]',
    `notes` STRING COMMENT 'Free-text field for capturing contextual notes, measurement caveats, methodology exceptions, or sponsor feedback related to this performance metric record. Used by sponsorship account managers during review and renewal negotiations.',
    `nps_lift` DECIMAL(18,2) COMMENT 'Change in Net Promoter Score for the sponsor brand attributable to the sponsorship activation, measured via fan/consumer surveys. Positive values indicate brand sentiment improvement driven by the partnership.',
    `reach_000s` DECIMAL(18,2) COMMENT 'Total unique audience reached by the sponsorship activation during the measurement period, expressed in thousands. Sourced from Nielsen or Kantar audience measurement panels.',
    `reporting_period_type` STRING COMMENT 'The cadence or granularity of the measurement reporting period. Aligns with contractual reporting obligations to sponsors (weekly, monthly, quarterly, seasonal, annual, or tied to a specific event).. Valid values are `weekly|monthly|quarterly|seasonal|annual|event_specific`',
    `social_engagement_rate` DECIMAL(18,2) COMMENT 'Percentage engagement rate for sponsor-related social media content during the measurement period ((likes + comments + shares + saves) / total impressions × 100). Sourced from Adobe Experience Platform social analytics.',
    `sponsor_verified` BOOLEAN COMMENT 'Indicates whether the sponsor has formally reviewed and accepted this performance metric measurement as accurate. Required for final ROI reporting and renewal negotiation documentation.',
    `sponsor_verified_timestamp` TIMESTAMP COMMENT 'Date and time when the sponsor formally verified and accepted this performance metric measurement. Null if sponsor_verified is False.',
    `unit_of_measure` STRING COMMENT 'The unit in which the metric value is expressed. Examples: seconds (broadcast airtime), impressions (digital/broadcast), GRP points (Gross Rating Points), CPM USD (Cost Per Mille in USD), score (brand recall/NPS), percentage (engagement rate). [ENUM-REF-CANDIDATE: seconds|impressions|grp_points|cpm_usd|score|percentage|mentions|clicks|views|reach_000s — 10 candidates stripped; promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when this performance metric record was most recently modified. Supports audit trail requirements, Silver Layer incremental processing, and SOX financial reporting controls.',
    `variance_pct` DECIMAL(18,2) COMMENT 'Percentage variance of actual performance against the contracted target value ((actual - target) / target * 100). Used in sponsor ROI dashboards and renewal negotiation scorecards.',
    `variance_value` DECIMAL(18,2) COMMENT 'Absolute difference between actual_value and contracted_target_value (actual minus target). Positive values indicate over-delivery; negative values indicate under-delivery against contracted KPI obligations.',
    CONSTRAINT pk_performance_metric PRIMARY KEY(`performance_metric_id`)
) COMMENT 'Transactional record capturing measured sponsorship performance data against contracted KPIs. Records metric type (GRP delivered, CPM realized, impressions, reach, frequency, brand recall score, NPS lift, social media engagement rate, broadcast airtime seconds, in-venue dwell time), measurement period, actual value, contracted target value, variance, measurement methodology, and data source (Nielsen, Kantar, internal analytics). Feeds ROI reporting and renewal negotiations.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`sponsorship`.`payment_schedule` (
    `payment_schedule_id` BIGINT COMMENT 'Unique surrogate identifier for the payment schedule milestone record within the sponsorship domain. Primary key for this entity.',
    `ar_invoice_id` BIGINT COMMENT 'Foreign key linking to finance.ar_invoice. Business justification: Each payment milestone triggers an AR invoice in the finance system. Finance uses this link for cash application, dunning, and revenue reporting. The denormalized `invoice_number` text field is replac',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: Payment schedules must post to the correct legal entitys books for intercompany billing, tax compliance, and SOX reporting. The existing sap_company_code plain attribute is a denormalized code; repla',
    `deal_id` BIGINT COMMENT 'Reference to the parent sponsorship deal contract that this payment schedule milestone belongs to. Links the milestone to its governing commercial agreement.',
    `deal_term_id` BIGINT COMMENT 'Foreign key linking to sponsorship.deal_term. Business justification: Payment schedule milestones are governed by specific deal terms — deal_term defines payment_schedule_type, invoice_milestone_count, late_payment_penalty_rate_pct, and escalation terms that directly dr',
    `fiscal_period_id` BIGINT COMMENT 'Foreign key linking to finance.fiscal_period. Business justification: Payment schedule milestones must align to fiscal periods for accrual accounting, cash flow forecasting, and period-close revenue recognition. Finance teams run period-level sponsorship cash receipt fo',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Payment milestones for franchise-specific sponsorship deals must be attributed to the franchise for AR management, franchise-level revenue allocation, and revenue-sharing calculations. Without this FK',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Payment milestones post to specific GL accounts (deferred revenue, sponsorship revenue receivable). Finance requires GL account assignment for accurate financial posting and period-end close. The deno',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Payment milestones are triggered by season events (season opener, playoff qualification, championship). Revenue recognition aligned to league season is a standard finance and audit requirement; struct',
    `nil_agreement_id` BIGINT COMMENT 'Foreign key linking to athlete.nil_agreement. Business justification: NIL deal payment tracking requires linking payment schedules to the specific NIL agreement being paid against. Finance and athlete management teams use this for NIL income reporting, agent commission ',
    `operator_id` BIGINT COMMENT 'Foreign key linking to gaming.operator. Business justification: Payment schedules for gaming operator sponsors require operator-level tracking for tax withholding compliance, regulatory remittance validation, and license status verification before payment release.',
    `regulatory_filing_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_filing. Business justification: Payment schedules involving withholding tax and cross-border payments require regulatory filings (tax authority filings, foreign payment disclosures). payment_schedule has withholding_tax_amount as a ',
    `revenue_recognition_schedule_id` BIGINT COMMENT 'Foreign key linking to finance.revenue_recognition_schedule. Business justification: ASC 606 / IFRS 15 requires sponsorship revenue to be recognized as performance obligations are satisfied, not when cash is received. Finance links each payment milestone to a recognition schedule to c',
    `sponsor_id` BIGINT COMMENT 'Reference to the sponsor (brand or corporate entity) responsible for this payment obligation. Supports accounts receivable aging and sponsor-level cash flow reporting.',
    `adjustment_amount` DECIMAL(18,2) COMMENT 'Monetary adjustment applied to the scheduled amount for this milestone, including contractual discounts, performance-based deductions, early payment incentives, or penalty surcharges. Negative values represent reductions; positive values represent surcharges.',
    `cost_center_code` STRING COMMENT 'SAP S/4HANA Controlling (CO) cost center code associated with the business unit responsible for fulfilling the sponsorship obligations tied to this payment milestone. Supports internal profitability analysis and EBITDA reporting.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this payment schedule milestone record was first created in the system. Supports audit trail, data lineage, and SOX financial controls compliance.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the payment milestone amounts (e.g., USD, EUR, GBP, AUD). Supports multi-currency sponsorship deals across global markets.. Valid values are `^[A-Z]{3}$`',
    `days_overdue` STRING COMMENT 'Number of calendar days this payment milestone is past its due_date without confirmed receipt. Calculated as current date minus due_date when payment_status is overdue. Used for accounts receivable aging buckets and collections escalation triggers.',
    `dispute_raised_date` DATE COMMENT 'Date on which the sponsor formally raised a dispute for this payment milestone. Null if no dispute has been raised. Used to track dispute resolution SLA compliance and aging.',
    `dispute_reason` STRING COMMENT 'Free-text description of the reason provided by the sponsor for disputing this payment milestone. Populated when payment_status is disputed. Supports dispute resolution tracking and contract management.',
    `due_date` DATE COMMENT 'Contractually agreed date by which the sponsor must remit this payment milestone. Used for accounts receivable aging, overdue detection, and cash flow forecasting in Workday Adaptive Planning.',
    `dunning_date` DATE COMMENT 'Date on which the most recent dunning (collections) notice was issued to the sponsor for this overdue payment milestone. Null if no dunning has been initiated. Used to track collections activity and enforce escalation timelines.',
    `dunning_level` STRING COMMENT 'Current dunning (collections escalation) level for this overdue payment milestone, as managed in SAP S/4HANA FI dunning procedures. Level 0 = no dunning initiated; higher levels indicate escalating collection notices sent to the sponsor.',
    `early_payment_discount_date` DATE COMMENT 'Last date by which the sponsor must remit payment to qualify for the early payment discount on this milestone. Null if no early payment discount applies.',
    `early_payment_discount_pct` DECIMAL(18,2) COMMENT 'Percentage discount offered to the sponsor for early payment of this milestone, as defined in the payment terms (e.g., 2.00 for a 2% early payment discount). Null if no early payment discount applies.',
    `forecast_period` STRING COMMENT 'Fiscal quarter in which this payment milestone is expected to be received for cash flow forecasting purposes, formatted as YYYY-Q{N} (e.g., 2025-Q2). Used in Workday Adaptive Planning for sponsorship revenue forecasting and EBITDA projections.. Valid values are `^[0-9]{4}-Q[1-4]$`',
    `invoice_date` DATE COMMENT 'Date on which the invoice was formally issued to the sponsor for this payment milestone. Establishes the billing cycle start for payment terms calculation and revenue recognition timing.',
    `late_fee_amount` DECIMAL(18,2) COMMENT 'Contractual late payment penalty fee assessed against the sponsor for overdue payment of this milestone, as defined in the sponsorship deal terms. Expressed in the deal currency. Zero or null if no late fee applies or has been assessed.',
    `milestone_name` STRING COMMENT 'Descriptive label for this payment milestone as defined in the sponsorship contract (e.g., Q1 Installment, Season Opener Activation Fee, Signing Bonus, Annual Naming Rights Fee). Used in sponsor communications and invoice descriptions.',
    `milestone_sequence` STRING COMMENT 'Ordinal position of this payment milestone within the overall deal payment schedule (e.g., 1 = first installment, 2 = second installment). Supports chronological ordering and installment tracking.',
    `net_amount` DECIMAL(18,2) COMMENT 'Final net amount due after applying all adjustments to the scheduled amount (scheduled_amount + adjustment_amount). This is the amount reflected on the issued invoice and tracked in SAP S/4HANA accounts receivable.',
    `notes` STRING COMMENT 'Free-text field for additional context, internal commentary, or special instructions related to this payment milestone (e.g., Sponsor requested 30-day extension per email dated 2025-01-15, VIK to be fulfilled via stadium signage Q2). For internal use by the sponsorship and finance teams.',
    `payment_method` STRING COMMENT 'Instrument or mechanism used by the sponsor to remit this payment (e.g., wire_transfer, ACH, check, credit_card, direct_debit, offset). Distinct from payment_type which captures the consideration form. Used for treasury reconciliation and PCI-DSS compliance tracking.. Valid values are `wire_transfer|ACH|check|credit_card|direct_debit|offset`',
    `payment_reference` STRING COMMENT 'Sponsor-provided remittance reference or bank transaction reference number accompanying the payment. Used for automated cash application and matching in SAP S/4HANA accounts receivable.',
    `payment_status` STRING COMMENT 'Current lifecycle state of this payment milestone. scheduled = not yet invoiced; invoiced = invoice issued awaiting receipt; received = funds confirmed; overdue = past due date without receipt; cancelled = milestone voided; disputed = sponsor has raised a formal dispute.. Valid values are `scheduled|invoiced|received|overdue|cancelled|disputed`',
    `payment_terms_code` STRING COMMENT 'SAP S/4HANA payment terms code governing the due date calculation and early payment discount conditions for this milestone (e.g., NET30, NET60, 2/10NET30). Derived from the sponsorship deal contract terms.',
    `payment_type` STRING COMMENT 'Classification of the payment consideration form. cash = monetary wire/ACH/check; VIK = Value-In-Kind (goods or services in lieu of cash); barter = reciprocal exchange of services; offset = applied against a credit balance; credit_note = formal credit adjustment. Drives revenue recognition treatment under ASC 606.. Valid values are `cash|VIK|barter|offset|credit_note`',
    `profit_center_code` STRING COMMENT 'SAP S/4HANA Controlling (CO) profit center code for revenue attribution of this payment milestone. Enables segment-level P&L reporting by league, venue, or business unit for management accounting and ROI analysis.',
    `received_amount` DECIMAL(18,2) COMMENT 'Actual amount received from the sponsor for this milestone. May differ from net_amount in cases of partial payment, short payment, or currency conversion variance. Null until payment is received.',
    `received_date` DATE COMMENT 'Actual date on which the sponsors payment was confirmed as received and cleared in the bank or SAP FI clearing account. Null when payment has not yet been received. Used for days-sales-outstanding (DSO) calculation and cash flow actuals.',
    `revenue_recognition_date` DATE COMMENT 'Date on which the revenue associated with this payment milestone is recognized in the financial statements under ASC 606 / IFRS 15. May differ from the received_date for multi-period or performance-obligation-based sponsorship deals.',
    `sap_fi_document_number` STRING COMMENT 'SAP S/4HANA Financial Accounting document number associated with the accounts receivable posting for this payment milestone. Serves as the primary cross-reference between the sponsorship data product and the general ledger for audit and reconciliation purposes.. Valid values are `^[0-9]{10}$`',
    `schedule_number` STRING COMMENT 'Externally-visible business identifier for this payment schedule milestone, formatted as PS-{YYYY}-{NNNNNN}. Used in sponsor-facing invoices, SAP FI correspondence, and accounts receivable reconciliation.. Valid values are `^PS-[0-9]{4}-[0-9]{6}$`',
    `scheduled_amount` DECIMAL(18,2) COMMENT 'Gross contractual amount due for this payment milestone as specified in the sponsorship deal. Represents the base obligation before any adjustments, discounts, or withholding taxes. Expressed in the deal currency.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this payment schedule milestone record was most recently modified. Tracks the latest change for audit trail, data lineage, and change management purposes.',
    `vik_description` STRING COMMENT 'Narrative description of the goods or services provided as Value-In-Kind (VIK) consideration for this milestone when payment_type is VIK or barter. Captures the nature, quantity, and estimated fair market value of the non-cash consideration for revenue recognition purposes.',
    `withholding_tax_amount` DECIMAL(18,2) COMMENT 'Amount of withholding tax deducted from this payment milestone by the sponsor, applicable for cross-border sponsorship deals subject to bilateral tax treaties. Impacts net cash received and requires separate GL posting in SAP S/4HANA.',
    CONSTRAINT pk_payment_schedule PRIMARY KEY(`payment_schedule_id`)
) COMMENT 'Master record defining the contractual payment milestones and installment schedule for a sponsorship deal. Captures milestone name, due date, payment amount, payment type (cash, VIK, barter), invoice reference, payment status (scheduled, invoiced, received, overdue), and SAP S/4HANA FI document number. Supports accounts receivable tracking and cash flow forecasting for the finance domain.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`sponsorship`.`property` (
    `property_id` BIGINT COMMENT 'Primary key for property',
    `access_zone_id` BIGINT COMMENT 'Foreign key linking to security.access_zone. Business justification: Sponsorship properties (naming rights assets, hospitality suites, field-level signage) are physically located within specific security access zones. Property managers and security ops need this link f',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Sponsorship properties are managed by specific business units with dedicated cost centers for maintenance, production, and operational cost allocation. Property-level P&L reporting requires cost cente',
    `fixed_asset_id` BIGINT COMMENT 'Foreign key linking to finance.fixed_asset. Business justification: Sponsorship properties (stadium signage, digital boards, naming rights assets) are registered as fixed assets for depreciation, insurance valuation, and capital expenditure tracking. Finance teams req',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Sponsorship properties are often franchise-owned assets — team jerseys, franchise arenas, team digital channels. Franchise attribution is required for property valuation, inventory management, and fra',
    `jurisdiction_id` BIGINT COMMENT 'Foreign key linking to gaming.jurisdiction. Business justification: Sponsorship properties (stadiums, broadcast slots, digital assets) have jurisdiction-specific gaming advertising restrictions. Property eligibility for gaming operator sponsorship and applicable regul',
    `league_id` BIGINT COMMENT 'Reference to the league or competition this property is part of, if applicable.',
    `parent_property_id` BIGINT COMMENT 'Self-referencing FK on property (parent_property_id)',
    `policy_id` BIGINT COMMENT 'Foreign key linking to compliance.policy. Business justification: Sponsorship properties are governed by specific compliance policies: ADA policies for venue properties, FCC policies for broadcast properties, GDPR policies for digital properties. Property managers i',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Sponsorship properties have season-specific availability, pricing, and inventory counts — a jersey patch property is available for a specific season. Season-scoped property planning, inventory availab',
    `segment_id` BIGINT COMMENT 'Foreign key linking to fan.segment. Business justification: Sponsorship properties are sold against specific fan audience segments (e.g., a youth-focused digital property targets the under-18 segment). Replacing the denormalized target_demographic plain attrib',
    `venue_id` BIGINT COMMENT 'Reference to the primary venue where this property takes place, if applicable.',
    `activation_lead_time_days` STRING COMMENT 'Minimum number of days required to activate a sponsorship for this property.',
    `base_sponsorship_value_usd` DECIMAL(18,2) COMMENT 'Base annual sponsorship value in US dollars for this property.',
    `broadcast_integration_available` BOOLEAN COMMENT 'Indicates whether broadcast sponsor integration opportunities are available.',
    `broadcast_reach` BIGINT COMMENT 'Estimated television and streaming viewership reach per occurrence.',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code for the primary market of this property.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this property record was first created in the system.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for sponsorship pricing.',
    `digital_activation_available` BOOLEAN COMMENT 'Indicates whether digital platform activation opportunities are available.',
    `digital_impressions` BIGINT COMMENT 'Estimated digital and social media impressions per occurrence or campaign period.',
    `effective_date` DATE COMMENT 'Date when this property became available for sponsorship or when current configuration became effective.',
    `estimated_annual_reach` BIGINT COMMENT 'Estimated total audience reach per year across all channels (live, broadcast, digital).',
    `estimated_live_attendance` STRING COMMENT 'Average or expected live in-person attendance per event occurrence.',
    `exclusivity_available` BOOLEAN COMMENT 'Indicates whether category exclusivity is available for this property.',
    `expiration_date` DATE COMMENT 'Date when this property will no longer be available for sponsorship or when current configuration expires.',
    `frequency_per_year` STRING COMMENT 'Number of times this property occurs annually (e.g., 52 for weekly show, 1 for annual event).',
    `geographic_market` STRING COMMENT 'Primary geographic market or region for this property.',
    `inventory_units_available` STRING COMMENT 'Total number of sponsorship inventory units available for this property (e.g., signage spots, ad slots).',
    `inventory_units_sold` STRING COMMENT 'Number of sponsorship inventory units currently sold or committed.',
    `jersey_sponsorship_available` BOOLEAN COMMENT 'Indicates whether jersey or uniform branding is available for this property.',
    `media_value_multiplier` DECIMAL(18,2) COMMENT 'Multiplier used to calculate equivalent media value for sponsorship exposure on this property.',
    `modified_by` STRING COMMENT 'User or system identifier that last modified this property record.',
    `modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this property record was last modified.',
    `naming_rights_available` BOOLEAN COMMENT 'Indicates whether naming rights sponsorship is available for this property.',
    `property_category` STRING COMMENT 'Business category segmenting the property for sponsorship packaging and pricing.',
    `property_code` STRING COMMENT 'Unique business identifier or code for the property used in contracts and inventory systems.',
    `property_description` STRING COMMENT 'Detailed description of the property including its sponsorship value proposition and audience reach.',
    `property_name` STRING COMMENT 'The official name of the sponsorable property (e.g., WrestleMania, Monday Night Raw, Royal Rumble Arena).',
    `property_status` STRING COMMENT 'Current lifecycle status of the property in the sponsorship inventory.',
    `property_tier` STRING COMMENT 'Sponsorship tier or premium level assigned to the property for pricing and packaging.',
    `property_type` STRING COMMENT 'Classification of the sponsorable property type.',
    `season_end_date` DATE COMMENT 'End date of the season or active period for this property.',
    `season_start_date` DATE COMMENT 'Start date of the season or active period for this property.',
    `created_by` STRING COMMENT 'User or system identifier that created this property record.',
    CONSTRAINT pk_property PRIMARY KEY(`property_id`)
) COMMENT 'Master reference table for property. Referenced by property_id.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`sponsorship`.`inventory_unit` (
    `inventory_unit_id` BIGINT COMMENT 'Primary key for inventory_unit',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Inventory units (jersey patches, in-arena LED signage, team digital overlays) are franchise-specific assets. Franchise-level inventory valuation, availability management, and rate card pricing require',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Inventory units (broadcast spots, signage placements, digital impressions) have base_rate_amount and revenue that must post to specific GL accounts by inventory type for revenue classification. Financ',
    `parent_inventory_unit_id` BIGINT COMMENT 'Self-referencing FK on inventory_unit (parent_inventory_unit_id)',
    `platform_channel_id` BIGINT COMMENT 'Foreign key linking to content.platform_channel. Business justification: Inventory units (digital ad slots, OTT pre-rolls, social placements) belong to specific platform channels. The existing `platform` text field is denormalized. Linking to platform_channel enables accur',
    `policy_id` BIGINT COMMENT 'Foreign key linking to compliance.policy. Business justification: Inventory unit definitions (broadcast slots, physical signage positions) are governed by compliance policies (FCC rules for broadcast units, ADA requirements for physical signage). Inventory unit setu',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Inventory units have season-specific availability windows, CPM benchmarks, and impression estimates. Season-scoped inventory planning, pre-season rate card publication, and season-end inventory utiliz',
    `type_id` BIGINT COMMENT 'Reference to the type of event where this inventory unit is activated (e.g., weekly show, pay-per-view, live event).',
    `venue_id` BIGINT COMMENT 'Reference to the venue where this inventory unit is located for venue-based sponsorship assets.',
    `base_rate_amount` DECIMAL(18,2) COMMENT 'Standard list price for this inventory unit before discounts or package pricing.',
    `cost_per_thousand_cpm` DECIMAL(18,2) COMMENT 'Cost per thousand impressions metric used for media buying comparisons and sponsor ROI analysis.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this inventory unit record was first created in the system.',
    `demographic_target` STRING COMMENT 'Primary demographic audience segment this inventory unit reaches (e.g., Adults 18-49, Males 25-54).',
    `duration_seconds` STRING COMMENT 'Length of exposure time in seconds for time-based inventory units (broadcast spots, digital video). Null for static placements.',
    `effective_end_date` DATE COMMENT 'Date when this inventory unit is retired or no longer available for sale. Null for ongoing availability.',
    `effective_start_date` DATE COMMENT 'Date when this inventory unit becomes available for sale and activation.',
    `exclusivity_category` STRING COMMENT 'Industry category for which exclusivity is granted (e.g., Automotive, Financial Services, Telecommunications).',
    `exclusivity_flag` BOOLEAN COMMENT 'Indicates whether this inventory unit offers category exclusivity to the sponsor (true) or allows multiple sponsors (false).',
    `format` STRING COMMENT 'Technical format specification for the inventory unit (e.g., 30-second video spot, 728x90 banner, 10x10 ft signage).',
    `frequency_cap` STRING COMMENT 'Maximum number of times this inventory unit can be activated per event or time period to prevent oversaturation.',
    `geographic_coverage` STRING COMMENT 'Geographic reach scope of the inventory unit for audience measurement and sponsor targeting.',
    `impressions_per_event` STRING COMMENT 'Estimated number of impressions delivered per event occurrence for this inventory unit.',
    `inventory_unit_category` STRING COMMENT 'High-level category grouping for the inventory unit used for portfolio management and reporting.',
    `inventory_unit_description` STRING COMMENT 'Detailed description of the inventory unit including placement, dimensions, duration, and visibility specifications.',
    `inventory_unit_status` STRING COMMENT 'Current lifecycle status of the inventory unit indicating availability for sale.',
    `lead_time_days` STRING COMMENT 'Number of days advance notice required for sponsor creative submission and activation of this inventory unit.',
    `maximum_availability_quantity` STRING COMMENT 'Maximum number of units available for sale per time period to maintain inventory scarcity and value.',
    `measurement_method` STRING COMMENT 'Methodology used to measure and report performance of this inventory unit (e.g., Nielsen Ratings, Google Analytics, Manual Count).',
    `minimum_commitment_quantity` STRING COMMENT 'Minimum number of units or activations required for purchase of this inventory unit.',
    `modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this inventory unit record was last updated.',
    `notes` STRING COMMENT 'Additional notes, restrictions, or special instructions for this inventory unit relevant to sales and fulfillment teams.',
    `package_eligible_flag` BOOLEAN COMMENT 'Indicates whether this inventory unit can be included in bundled sponsorship packages (true) or must be sold standalone (false).',
    `placement_location` STRING COMMENT 'Physical or digital location where the sponsorship asset appears (e.g., Arena North Entrance, Broadcast Overlay, Mobile App Home Screen).',
    `production_requirements` STRING COMMENT 'Technical specifications and production requirements for sponsor creative assets (file formats, dimensions, lead times).',
    `rate_currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for the base rate amount.',
    `rate_unit` STRING COMMENT 'Unit of measure for the base rate pricing (e.g., per event, per season, per thousand impressions).',
    `reach_estimate` STRING COMMENT 'Estimated unique audience reach for this inventory unit across all distribution channels.',
    `seasonality_flag` BOOLEAN COMMENT 'Indicates whether this inventory unit is available year-round (false) or only during specific seasons or events (true).',
    `unit_code` STRING COMMENT 'Business identifier code for the inventory unit used in sponsor proposals and contracts.',
    `unit_name` STRING COMMENT 'Human-readable name of the sponsorship inventory unit (e.g., Ring Apron Logo, Broadcast Lower Third, Jersey Patch).',
    `unit_type` STRING COMMENT 'Classification of the inventory unit by media channel or activation type.',
    `visibility_rating` STRING COMMENT 'Qualitative rating of the inventory units prominence and visibility to audiences.',
    CONSTRAINT pk_inventory_unit PRIMARY KEY(`inventory_unit_id`)
) COMMENT 'Master reference table for inventory_unit. Referenced by inventory_unit_id.';

